UPDATE manhaj_lessons SET blocks = blocks || '[{"type": "paragraph", "md": "عَنْ عَبْدِ اللَّهِ بْنِ مُغَفَّلٍ رضي الله عنه ، أَنَّهُ رَأَى رَجُلًا يَخْذِفُ فَقَالَ لَهُ: لَا تَخْذِفْ؛ فَإِنَّ رَسُولَ اللَّهِ صلى الله عليه وسلم نَهَى عَنِ الْخَذْفِ - أَوْ كَانَ يَكْرَهُ الْخَذْفَ - وَقَالَ: (إِنَّهُ لَا يُصَادُ بِهِ صَيْدٌ، وَلَا يُنْكَى بِهِ عَدُوٌّ، وَلَكِنَّهَا قَدْ ‌تَكْسِرُ ‌السِّنَّ وَتَفْقَأُ الْعَيْنَ)، ثُمَّ رآهُ بَعْدَ ذَلِكَ يَخْذِفُ فَقَالَ لَهُ: أُحَدِّثُكَ عَنْ رَسُولِ اللَّهِ صلى الله عليه وسلم أَنَّهُ نَهَى عَنِ الْخَذْفِ - أَوْ كَرِهَ الْخَذْفَ - وَأَنْتَ تَخْذِفُ! لَا أُكَلِّمُكَ كَذَا وَكَذَا [متفق عليه].", "page": 96, "id": "unit-09__lesson-02__b01", "inline": [{"t": "text", "s": "عَنْ عَبْدِ اللَّهِ بْنِ مُغَفَّلٍ "}, {"t": "honorific", "s": "رضي الله عنه"}, {"t": "text", "s": " ، أَنَّهُ رَأَى رَجُلًا يَخْذِفُ فَقَالَ لَهُ: لَا تَخْذِفْ؛ فَإِنَّ رَسُولَ اللَّهِ "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " نَهَى عَنِ الْخَذْفِ - أَوْ كَانَ يَكْرَهُ الْخَذْفَ - وَقَالَ: (إِنَّهُ لَا يُصَادُ بِهِ صَيْدٌ، وَلَا يُنْكَى بِهِ عَدُوٌّ، وَلَكِنَّهَا قَدْ ‌تَكْسِرُ ‌السِّنَّ وَتَفْقَأُ الْعَيْنَ)، ثُمَّ رآهُ بَعْدَ ذَلِكَ يَخْذِفُ فَقَالَ لَهُ: أُحَدِّثُكَ عَنْ رَسُولِ اللَّهِ "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " أَنَّهُ نَهَى عَنِ الْخَذْفِ - أَوْ كَرِهَ الْخَذْفَ - وَأَنْتَ تَخْذِفُ! لَا أُكَلِّمُكَ كَذَا وَكَذَا "}, {"t": "citation", "s": "[متفق عليه]", "source": "متفق عليه"}, {"t": "text", "s": "."}]}, {"type": "heading", "level": 3, "text": "أهداف الدرس:", "page": 96, "id": "unit-09__lesson-02__b02", "role": "objectives"}, {"type": "paragraph", "md": "معرفة أحد أصحاب النبي صلى الله عليه وسلم .", "page": 96, "id": "unit-09__lesson-02__b03", "inline": [{"t": "text", "s": "معرفة أحد أصحاب النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " ."}]}, {"type": "paragraph", "md": "التعرف على حكم شرعي قل من يلتفت إليه وهو حرمة الخذف والرمي بالحجر على المسلمين.", "page": 96, "id": "unit-09__lesson-02__b04"}, {"type": "heading", "level": 3, "text": "التعريف براوي الحديث:", "page": 96, "id": "unit-09__lesson-02__b05", "role": "definitions"}, {"type": "paragraph", "md": "‌عبد ‌الله ‌بن ‌مُغَفَّل بن غَنْم المُزَني: بايع بيعة الرضوان تحت الشجرة، وكان يمسك بأغصانها عن وجه رسول الله صلى الله عليه وسلم ، من فقهاء الصحابة؛ فقد كان أحد العشرة الذين بعثهم عمر رضي الله عنه إلى البصرة ليفقهوا الناس، سكن المدينة، ثم تحول إلى البصرة، وبها مات سنة تسع وخمسين رضي الله عنه .", "page": 96, "id": "unit-09__lesson-02__b06", "inline": [{"t": "text", "s": "‌عبد ‌الله ‌بن ‌مُغَفَّل بن غَنْم المُزَني: بايع بيعة الرضوان تحت الشجرة، وكان يمسك بأغصانها عن وجه رسول الله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " ، من فقهاء الصحابة؛ فقد كان أحد العشرة الذين بعثهم عمر "}, {"t": "honorific", "s": "رضي الله عنه"}, {"t": "text", "s": " إلى البصرة ليفقهوا الناس، سكن المدينة، ثم تحول إلى البصرة، وبها مات سنة تسع وخمسين "}, {"t": "honorific", "s": "رضي الله عنه"}, {"t": "text", "s": " ."}]}, {"type": "heading", "level": 3, "text": "شرح الحديث وبيان معانيه:", "page": 96, "id": "unit-09__lesson-02__b07", "role": "hadith_explanation"}, {"type": "paragraph", "md": "الخَذْف -بالخاء-: رمي الإنسان بحصاة أو نواة ونحوهما يجعلهما بين أصبعيه السبابتين أو الإبهام والسبابة، وإن قلتَ: الحَذْف -بالحاء- فهو الرمي بالعصا؛ كما حَذَف المجاهد القائد يحيى السنوار عصاه على اليهود لما لم يجد شيئًا يرميهم به إلا العصا، ثم ارتقى شهيدًا مقبلا غيرَ مدبر.", "page": 96, "id": "unit-09__lesson-02__b08"}, {"type": "paragraph", "md": "قوله: (ولا تنكأ) أي: لا تجرح ولا تثخن، وقوله: (تفقأ) أي: تقلع العين أو تجعلها عوراء.", "page": 96, "id": "unit-09__lesson-02__b09", "inline": [{"t": "text", "s": "قوله: "}, {"t": "emphasis", "s": "(ولا تنكأ)", "role": "lemma"}, {"t": "text", "s": " أي: لا تجرح ولا تثخن، وقوله: "}, {"t": "emphasis", "s": "(تفقأ)", "role": "lemma"}, {"t": "text", "s": " أي: تقلع العين أو تجعلها عوراء."}]}, {"type": "heading", "level": 3, "text": "فوائد ومسائل في الحديث النبوي الشريف:", "page": 96, "id": "unit-09__lesson-02__b10", "role": "benefits"}, {"type": "paragraph", "md": "في الحديث دليل على تحريم الخذف؛ لأن الرسول صلى الله عليه وسلم نهى عنه، والنهي للتحريم؛ لأنه لا مصلحة فيه، ويخاف مفسدته؛ لأنه يكسر السن، ويفقأ العين، ولا يحصل به الاصطياد؛ لأن الصيد إنما يحل بنهر الدم، وأما الخذف فإنه ليس بمحدد، بل يَقتل الصيد بقوة راميه لا بحده، فالمقتول به يكون وقيذًا.", "page": 96, "id": "unit-09__lesson-02__b11", "inline": [{"t": "text", "s": "في الحديث دليل على تحريم الخذف؛ لأن الرسول "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " نهى عنه، والنهي للتحريم؛ لأنه لا مصلحة فيه، ويخاف مفسدته؛ لأنه يكسر السن، ويفقأ العين، ولا يحصل به الاصطياد؛ لأن الصيد إنما يحل بنهر الدم، وأما الخذف فإنه ليس بمحدد، بل يَقتل الصيد بقوة راميه لا بحده، فالمقتول به يكون وقيذًا."}]}, {"type": "paragraph", "md": "الصيد الذي يُصاد بإطلاق النار بالبنادق الآلية مباح وهو من صور التذكية المشروعة؛ لأن الرَّصاصة لا تضغط على جسم الصَّيد فقط -كما في حالة استخدام الحَجَر أو الصَّخْر أو العَصَا الغليظة-، بل هي في الواقع تقطع الجِلْد، وتُمزِّق الجسم، وتُسيلُ الدَّمَ؛ فلا يكون الصَّيد المقتول بالبُندقيَّة من قبيل المَوْقوذَة المشار إليها في القرآن، بل يكون كالمذبوح بالآلة التي تُسيلُ الدَّم وتقضي على الحياة.", "page": 97, "id": "unit-09__lesson-02__b12"}, {"type": "paragraph", "md": "نهيُ النبي صلى الله عليه وسلم عن الخذف؛ وفي هذا دليل على وجوب المحافظة على سلامة الناس من الأذى، ولما كان الخذف ليس من آلات الحرب التي يتمرن بها التمرن الجائز مثل رمي السهام أو الطلقات النارية، ولا هو من آلات الصيد فينتفع به؛ فليس فيه أي منفعة؛ حرمت الشريعة اللهو به؛ خاصة مع ما يخشى من عقباه من كسر السن وفقء العين، وعلى هذا فاللعب بين الصبيان برمي الحجارة على بعضهم أو مسدسات «الخروق» وكل ما يؤدي للأذى بدون تحقيق غاية شرعية في التدريب: كلها ألعاب محرمة ممنوعة، ويحب على أولياء أمور الصبيان منعهم من استعمالها وبيان البدائل الشرعية لهم اتباعا لهدي النبي صلى الله عليه وسلم .", "page": 97, "id": "unit-09__lesson-02__b13", "inline": [{"t": "text", "s": "نهيُ النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " عن الخذف؛ وفي هذا دليل على وجوب المحافظة على سلامة الناس من الأذى، ولما كان الخذف ليس من آلات الحرب التي يتمرن بها التمرن الجائز مثل رمي السهام أو الطلقات النارية، ولا هو من آلات الصيد فينتفع به؛ فليس فيه أي منفعة؛ حرمت الشريعة اللهو به؛ خاصة مع ما يخشى من عقباه من كسر السن وفقء العين، وعلى هذا فاللعب بين الصبيان برمي الحجارة على بعضهم أو مسدسات "}, {"t": "quote", "s": "الخروق"}, {"t": "text", "s": " وكل ما يؤدي للأذى بدون تحقيق غاية شرعية في التدريب: كلها ألعاب محرمة ممنوعة، ويحب على أولياء أمور الصبيان منعهم من استعمالها وبيان البدائل الشرعية لهم اتباعا لهدي النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " ."}]}, {"type": "paragraph", "md": "في قول عبد الله بن مغفل رضي الله عنه : (لا أكلمك أبدًا) دليل على مشروعية هجر من خالف الشرع وارتكب المعصية عن علم تأديبًا له وزجرًا حتى يرجع عن ذلك؛ هذا إن كان الهجر أصلح في حقه.", "page": 97, "id": "unit-09__lesson-02__b14", "inline": [{"t": "text", "s": "في قول عبد الله بن مغفل "}, {"t": "honorific", "s": "رضي الله عنه"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(لا أكلمك أبدًا)", "role": "emphasis"}, {"t": "text", "s": " دليل على مشروعية هجر من خالف الشرع وارتكب المعصية عن علم تأديبًا له وزجرًا حتى يرجع عن ذلك؛ هذا إن كان الهجر أصلح في حقه."}]}, {"type": "paragraph", "md": "وهذا يدلك على شدة اتباع الصحابة للرسول صلى الله عليه وسلم دون أن يسألوا عن علة الحكم؛ فإنهم ولو لم يروا الحكمة من الفعل يتبعون الرسول صلى الله عليه وسلم ويوالون الناس على ذلك", "page": 97, "id": "unit-09__lesson-02__b15", "inline": [{"t": "text", "s": "وهذا يدلك على شدة اتباع الصحابة للرسول "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " دون أن يسألوا عن علة الحكم؛ فإنهم ولو لم يروا الحكمة من الفعل يتبعون الرسول "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " ويوالون الناس على ذلك"}]}, {"type": "paragraph", "md": "وفي الحديث دليلٌ على أهمية اختيار أجود أنواع الأسلحة لقتال العدو، وحرمة استعمال الأسلحة الفاسدة التي قد تضر من يستعملها ولا تحقق نكايةً في العدو ولا نصرًا أمامه.", "page": 97, "id": "unit-09__lesson-02__b16"}, {"type": "heading", "level": 3, "text": "التقويم والأسئلة:", "page": 97, "id": "unit-09__lesson-02__b17", "role": "assessment"}, {"type": "paragraph", "md": "ما الخذف المذكور في الحديث؟ وما الفرق بينه وبين الحذف؟", "page": 97, "id": "unit-09__lesson-02__b18", "item_role": "question"}, {"type": "paragraph", "md": "ما حكم الصيد الذي يُصاد بالمثقل؟ وهل يدخل في الحكم: الصيد بإطلاق النار؟", "page": 97, "id": "unit-09__lesson-02__b19", "item_role": "question"}, {"type": "paragraph", "md": "ما حكم هجر مَن علم بالسنة والأمر الشرعي فترك اتباعه تقصيرًا منه إن كان الهجر يردعه؟", "page": 97, "id": "unit-09__lesson-02__b20", "item_role": "question"}, {"type": "heading", "level": 3, "text": "نشاط من كتاب", "page": 97, "id": "unit-09__lesson-02__b21", "role": "activity"}, {"type": "paragraph", "md": "في هذا الحديثِ دليل على وجوب اتباع النبي صلى الله عليه وسلم ، وثمة أحاديث كثيرة في هذا المعنى.. ارجع إلى كتب السنة واستخرج ثلاثة أحاديث وثلاثة قصص في هذا الموضوع", "page": 97, "id": "unit-09__lesson-02__b22", "inline": [{"t": "text", "s": "في هذا الحديثِ دليل على وجوب اتباع النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " ، وثمة أحاديث كثيرة في هذا المعنى.. ارجع إلى كتب السنة واستخرج ثلاثة أحاديث وثلاثة قصص في هذا الموضوع"}], "item_role": "activity_step"}]' WHERE id='unit-09__lesson-02';
INSERT INTO manhaj_lessons (id,unit_id,ord,title,subject,duration_min,hadith_count,quran_count,blocks) VALUES ('unit-09__lesson-03','unit-09',3,'شروط لا إله إلا الله','التوحيد والعقيدة',NULL,0,10,'');
UPDATE manhaj_lessons SET blocks = blocks || '[{"type": "heading", "level": 3, "text": "أهداف الدرس:", "page": 98, "id": "unit-09__lesson-03__b01", "role": "objectives"}, {"type": "paragraph", "md": "بيان شروط كلمة التوحيد السبعة؛ التي يصح بها الإسلام ظاهرًا وباطنًا.", "page": 98, "id": "unit-09__lesson-03__b02"}, {"type": "paragraph", "md": "التنبيه على أن عوام المسلمين يعملون بمضمون هذه الشروط وإن لم ينصوا عليها، وهو صحيح.", "page": 98, "id": "unit-09__lesson-03__b03"}, {"type": "heading", "level": 3, "text": "أهمية معرفة شروط كلمة التوحيد:", "page": 98, "id": "unit-09__lesson-03__b04", "role": "section"}, {"type": "paragraph", "md": "لكلمة التوحيد سبعة شروط: من لم يحققها؛ فلن ينتفع بقولها، ولو رددها ألف مرة يوميا، ومن حققها عمليا (حتى لو لم يستطع التعبير عنها بلسانه) فستكون نجاة له في الآخرة، ونجاة له من النار، وسعادة له في الدنيا؛ قال رسول الله صلى الله عليه وسلم : (لن يوافي عبد يوم القيامة يقول لا إله إلا الله يبتغي بذلك وجه الله إلا حرم على النار)، وقال تعالى: ﴿وَمَنۡ أَعۡرَضَ عَن ذِكۡرِي فَإِنَّ لَهُۥ مَعِيشَةٗ ضَنكٗا﴾.", "page": 98, "id": "unit-09__lesson-03__b05", "inline": [{"t": "text", "s": "لكلمة التوحيد سبعة شروط: من لم يحققها؛ فلن ينتفع بقولها، ولو رددها ألف مرة يوميا، ومن حققها عمليا "}, {"t": "emphasis", "s": "(حتى لو لم يستطع التعبير عنها بلسانه)", "role": "emphasis"}, {"t": "text", "s": " فستكون نجاة له في الآخرة، ونجاة له من النار، وسعادة له في الدنيا؛ قال رسول الله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(لن يوافي عبد يوم القيامة يقول لا إله إلا الله يبتغي بذلك وجه الله إلا حرم على النار)", "role": "emphasis"}, {"t": "text", "s": "، وقال تعالى: "}, {"t": "ayah", "s": "وَمَنۡ أَعۡرَضَ عَن ذِكۡرِي فَإِنَّ لَهُۥ مَعِيشَةٗ ضَنكٗا", "ayah": [], "verses": [{"n": 124, "text": "وَمَنۡ أَعۡرَضَ عَن ذِكۡرِي فَإِنَّ لَهُۥ مَعِيشَةٗ ضَنكٗا", "surah": 20, "surah_name": "طه", "ref": "20:124", "ref_api": "https://api.quran.com/api/v4/verses/by_key/20:124"}], "surah": 20, "ref_api": "https://api.quran.com/api/v4/verses/by_key/20:124", "surah_name": "طه", "ayah_canonical": 124, "match": "contained", "ref": "20:124"}, {"t": "text", "s": "."}]}, {"type": "heading", "level": 3, "text": "وشروط كلمة التوحيد السبعة هي:", "page": 98, "id": "unit-09__lesson-03__b06", "role": "section"}, {"type": "paragraph", "md": "1- العلم: بمعناها نفيا وإثباتا: ﴿فَٱعۡلَمۡ أَنَّهُۥ لَآ إِلَٰهَ إِلَّا ٱللَّهُ﴾؛ فيعلم حقيقة هذه الكلمة ومقتضياتها.", "page": 98, "id": "unit-09__lesson-03__b07", "inline": [{"t": "text", "s": "1- "}, {"t": "emphasis", "s": "العلم", "role": "emphasis"}, {"t": "text", "s": ": بمعناها نفيا وإثباتا: "}, {"t": "ayah", "s": "فَٱعۡلَمۡ أَنَّهُۥ لَآ إِلَٰهَ إِلَّا ٱللَّهُ", "ayah": [], "verses": [{"n": 19, "text": "فَٱعۡلَمۡ أَنَّهُۥ لَآ إِلَٰهَ إِلَّا ٱللَّهُ", "surah": 47, "surah_name": "محمد", "ref": "47:19", "ref_api": "https://api.quran.com/api/v4/verses/by_key/47:19"}], "surah": 47, "ref_api": "https://api.quran.com/api/v4/verses/by_key/47:19", "surah_name": "محمد", "ayah_canonical": 19, "match": "contained", "ref": "47:19"}, {"t": "text", "s": "؛ فيعلم حقيقة هذه الكلمة ومقتضياتها."}], "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- اليقين: أن يكون قائلها على يقين تام بأن الله هو المعبود بحق: ﴿إِنَّمَا ٱلۡمُؤۡمِنُونَ ٱلَّذِينَ ءَامَنُواْ بِٱللَّهِ وَرَسُولِهِۦ ثُمَّ لَمۡ يَرۡتَابُواْ وَجَٰهَدُواْ بِأَمۡوَٰلِهِمۡ وَأَنفُسِهِمۡ فِي سَبِيلِ ٱللَّهِۚ أُوْلَٰٓئِكَ هُمُ ٱلصَّٰدِقُونَ ۝١٥﴾.", "page": 98, "id": "unit-09__lesson-03__b08", "inline": [{"t": "emphasis", "s": "2- اليقين", "role": "emphasis"}, {"t": "text", "s": ": أن يكون قائلها على يقين تام بأن الله هو المعبود بحق: "}, {"t": "ayah", "s": "إِنَّمَا ٱلۡمُؤۡمِنُونَ ٱلَّذِينَ ءَامَنُواْ بِٱللَّهِ وَرَسُولِهِۦ ثُمَّ لَمۡ يَرۡتَابُواْ وَجَٰهَدُواْ بِأَمۡوَٰلِهِمۡ وَأَنفُسِهِمۡ فِي سَبِيلِ ٱللَّهِۚ أُوْلَٰٓئِكَ هُمُ ٱلصَّٰدِقُونَ ۝١٥", "ayah": [15], "verses": [{"n": 15, "text": "إِنَّمَا ٱلۡمُؤۡمِنُونَ ٱلَّذِينَ ءَامَنُواْ بِٱللَّهِ وَرَسُولِهِۦ ثُمَّ لَمۡ يَرۡتَابُواْ وَجَٰهَدُواْ بِأَمۡوَٰلِهِمۡ وَأَنفُسِهِمۡ فِي سَبِيلِ ٱللَّهِۚ أُوْلَٰٓئِكَ هُمُ ٱلصَّٰدِقُونَ", "surah": 49, "ref_api": "https://api.quran.com/api/v4/verses/by_key/49:15", "surah_name": "الحجرات", "ayah_canonical": 15, "match": "exact", "ref": "49:15"}], "surah": null, "ref_api": null}, {"t": "text", "s": "."}], "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "3- القَبول: بأن يقبل المسلم ما دلت عليه مِن إخلاص العبادة لله وترك عبادة ما سواه؛ قال تعالى عن فرعون وقومه ﴿وَجَحَدُواْ بِهَا وَٱسۡتَيۡقَنَتۡهَآ أَنفُسُهُمۡ ظُلۡمٗا وَعُلُوّٗاۚ﴾؛ فكان عندهم علم ويقين ولكن لم يقبلوا قولها والالتزام بها فصاروا من أصحاب النار، وكذلك أبو طالب -عم النبي صلى الله عليه وسلم - علم واستيقن برسالة النبي صلى الله عليه وسلم لكنه لم يقبل الدخول في دينه؛ فصار من أصحاب الجحيم.", "page": 98, "id": "unit-09__lesson-03__b09", "inline": [{"t": "text", "s": "3- "}, {"t": "emphasis", "s": "القَبول", "role": "emphasis"}, {"t": "text", "s": ": بأن يقبل المسلم ما دلت عليه مِن إخلاص العبادة لله وترك عبادة ما سواه؛ قال تعالى عن فرعون وقومه "}, {"t": "ayah", "s": "وَجَحَدُواْ بِهَا وَٱسۡتَيۡقَنَتۡهَآ أَنفُسُهُمۡ ظُلۡمٗا وَعُلُوّٗاۚ", "ayah": [], "verses": [{"n": 14, "text": "وَجَحَدُواْ بِهَا وَٱسۡتَيۡقَنَتۡهَآ أَنفُسُهُمۡ ظُلۡمٗا وَعُلُوّٗاۚ", "surah": 27, "surah_name": "النمل", "ref": "27:14", "ref_api": "https://api.quran.com/api/v4/verses/by_key/27:14"}], "surah": 27, "ref_api": "https://api.quran.com/api/v4/verses/by_key/27:14", "surah_name": "النمل", "ayah_canonical": 14, "match": "contained", "ref": "27:14"}, {"t": "text", "s": "؛ فكان عندهم علم ويقين ولكن لم يقبلوا قولها والالتزام بها فصاروا من أصحاب النار، وكذلك أبو طالب -عم النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " - علم واستيقن برسالة النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " لكنه لم يقبل الدخول في دينه؛ فصار من أصحاب الجحيم."}], "list": {"type": "ordered", "marker": "3"}}, {"type": "paragraph", "md": "4- الانقياد: أن تنقاد لأوامر الله سبحانه وتسلم لها، قال تعالى: ﴿فَلَا وَرَبِّكَ لَا يُؤۡمِنُونَ حَتَّىٰ يُحَكِّمُوكَ فِيمَا شَجَرَ بَيۡنَهُمۡ ثُمَّ لَا يَجِدُواْ فِيٓ أَنفُسِهِمۡ حَرَجٗا مِّمَّا قَضَيۡتَ وَيُسَلِّمُواْ تَسۡلِيمٗا ۝٦٥، وبسبب تخلف شرط الانقياد كفر إبليس رغم أنه كان يعلم ويوقن ويقبل بلا إله إلا الله: ﴿وَإِذۡ قُلۡنَا لِلۡمَلَٰٓئِكَةِ ٱسۡجُدُواْ لِأٓدَمَ فَسَجَدُوٓاْ إِلَّآ إِبۡلِيسَ أَبَىٰ وَٱسۡتَكۡبَرَ وَكَانَ مِنَ ٱلۡكَٰفِرِينَ ۝٣٤﴾. ومِن تَرْك الانقياد للدين: تحكيم القوانين الوضعية الكفرية في البلاد والعباد، يقول ابن كثير رحمه الله : «فمن ترك الشرع المحكم المنزل على محمد بن عبد الله خاتم الأنبياء وتحاكم إلى غيره من الشرائع المنسوخة فقد كفر، فكيف بمن تحاكم إلى الياسا، وقدمها عليه؟! فمن فعل ذلك كفر بإجماع المسلمين»، فالتشريع مع الله كفر وهو مخالف لشرط الانقياد مخالفة قطعية.", "page": 98, "id": "unit-09__lesson-03__b10", "inline": [{"t": "text", "s": "4- "}, {"t": "emphasis", "s": "الانقياد", "role": "emphasis"}, {"t": "text", "s": ": أن تنقاد لأوامر الله سبحانه وتسلم لها، قال تعالى: "}, {"t": "ayah", "s": "فَلَا وَرَبِّكَ لَا يُؤۡمِنُونَ حَتَّىٰ يُحَكِّمُوكَ فِيمَا شَجَرَ بَيۡنَهُمۡ ثُمَّ لَا يَجِدُواْ فِيٓ أَنفُسِهِمۡ حَرَجٗا مِّمَّا قَضَيۡتَ وَيُسَلِّمُواْ تَسۡلِيمٗا ۝٦٥، وبسبب تخلف شرط الانقياد كفر إبليس رغم أنه كان يعلم ويوقن ويقبل بلا إله إلا الله: ﴿وَإِذۡ قُلۡنَا لِلۡمَلَٰٓئِكَةِ ٱسۡجُدُواْ لِأٓدَمَ فَسَجَدُوٓاْ إِلَّآ إِبۡلِيسَ أَبَىٰ وَٱسۡتَكۡبَرَ وَكَانَ مِنَ ٱلۡكَٰفِرِينَ ۝٣٤", "ayah": [65, 34], "verses": [{"n": 65, "text": "فَلَا وَرَبِّكَ لَا يُؤۡمِنُونَ حَتَّىٰ يُحَكِّمُوكَ فِيمَا شَجَرَ بَيۡنَهُمۡ ثُمَّ لَا يَجِدُواْ فِيٓ أَنفُسِهِمۡ حَرَجٗا مِّمَّا قَضَيۡتَ وَيُسَلِّمُواْ تَسۡلِيمٗا", "surah": 4, "ref_api": "https://api.quran.com/api/v4/verses/by_key/4:65", "surah_name": "النساء", "ayah_canonical": 65, "match": "exact", "ref": "4:65"}, {"n": 34, "text": "، وبسبب تخلف شرط الانقياد كفر إبليس رغم أنه كان يعلم ويوقن ويقبل بلا إله إلا الله: ﴿وَإِذۡ قُلۡنَا لِلۡمَلَٰٓئِكَةِ ٱسۡجُدُواْ لِأٓدَمَ فَسَجَدُوٓاْ إِلَّآ إِبۡلِيسَ أَبَىٰ وَٱسۡتَكۡبَرَ وَكَانَ مِنَ ٱلۡكَٰفِرِينَ", "surah": null, "ref_api": null}], "surah": null, "ref_api": null}, {"t": "text", "s": ". ومِن تَرْك "}, {"t": "emphasis", "s": "الانقياد", "role": "emphasis"}, {"t": "text", "s": " للدين: تحكيم القوانين الوضعية الكفرية في البلاد والعباد، يقول ابن كثير "}, {"t": "honorific", "s": "رحمه الله"}, {"t": "text", "s": " : "}, {"t": "quote", "s": "فمن ترك الشرع المحكم المنزل على محمد بن عبد الله خاتم الأنبياء وتحاكم إلى غيره من الشرائع المنسوخة فقد كفر، فكيف بمن تحاكم إلى الياسا، وقدمها عليه؟! فمن فعل ذلك كفر بإجماع المسلمين", "speaker": "ابن كثير رحمه الله"}, {"t": "text", "s": "، فالتشريع مع الله كفر وهو مخالف لشرط "}, {"t": "emphasis", "s": "الانقياد", "role": "emphasis"}, {"t": "text", "s": " مخالفة قطعية."}], "list": {"type": "ordered", "marker": "4"}}, {"type": "paragraph", "md": "5- الصدق: أن تقولها وأنت صادقٌ في ذلك، يطابق قلبك لسانك، قال تعالى: ﴿إِذَا جَآءَكَ ٱلۡمُنَٰفِقُونَ قَالُواْ نَشۡهَدُ إِنَّكَ لَرَسُولُ ٱللَّهِۗ وَٱللَّهُ يَعۡلَمُ إِنَّكَ لَرَسُولُهُۥ وَٱللَّهُ يَشۡهَدُ إِنَّ ٱلۡمُنَٰفِقِينَ لَكَٰذِبُونَ ۝١﴾، وقال تعالى: ﴿فَلَيَعۡلَمَنَّ ٱللَّهُ ٱلَّذِينَ صَدَقُواْ وَلَيَعۡلَمَنَّ ٱلۡكَٰذِبِينَ ۝٣﴾.", "page": 99, "id": "unit-09__lesson-03__b11", "inline": [{"t": "text", "s": "5- "}, {"t": "emphasis", "s": "الصدق", "role": "emphasis"}, {"t": "text", "s": ": أن تقولها وأنت صادقٌ في ذلك، يطابق قلبك لسانك، قال تعالى: "}, {"t": "ayah", "s": "إِذَا جَآءَكَ ٱلۡمُنَٰفِقُونَ قَالُواْ نَشۡهَدُ إِنَّكَ لَرَسُولُ ٱللَّهِۗ وَٱللَّهُ يَعۡلَمُ إِنَّكَ لَرَسُولُهُۥ وَٱللَّهُ يَشۡهَدُ إِنَّ ٱلۡمُنَٰفِقِينَ لَكَٰذِبُونَ ۝١", "ayah": [1], "verses": [{"n": 1, "text": "إِذَا جَآءَكَ ٱلۡمُنَٰفِقُونَ قَالُواْ نَشۡهَدُ إِنَّكَ لَرَسُولُ ٱللَّهِۗ وَٱللَّهُ يَعۡلَمُ إِنَّكَ لَرَسُولُهُۥ وَٱللَّهُ يَشۡهَدُ إِنَّ ٱلۡمُنَٰفِقِينَ لَكَٰذِبُونَ", "surah": 63, "ref_api": "https://api.quran.com/api/v4/verses/by_key/63:1", "surah_name": "المنافقون", "ayah_canonical": 1, "match": "exact", "ref": "63:1"}], "surah": null, "ref_api": null}, {"t": "text", "s": "، وقال تعالى: "}, {"t": "ayah", "s": "فَلَيَعۡلَمَنَّ ٱللَّهُ ٱلَّذِينَ صَدَقُواْ وَلَيَعۡلَمَنَّ ٱلۡكَٰذِبِينَ ۝٣", "ayah": [3], "verses": [{"n": 3, "text": "فَلَيَعۡلَمَنَّ ٱللَّهُ ٱلَّذِينَ صَدَقُواْ وَلَيَعۡلَمَنَّ ٱلۡكَٰذِبِينَ", "surah": 29, "ref_api": "https://api.quran.com/api/v4/verses/by_key/29:3", "surah_name": "العنكبوت", "ayah_canonical": 3, "match": "contained", "ref": "29:3"}], "surah": null, "ref_api": null}, {"t": "text", "s": "."}], "list": {"type": "ordered", "marker": "5"}}, {"type": "paragraph", "md": "6- الإخلاص: ألا يطلب بهذه الكلمة إلا وجه الله وحده، ﴿وَمَآ أُمِرُوٓاْ إِلَّا لِيَعۡبُدُواْ ٱللَّهَ مُخۡلِصِينَ لَهُ ٱلدِّينَ﴾، وقال رسول الله صلى الله عليه وسلم : (إن الله حرَّم على النار من قال: لا إله إلا الله يبتغي بذلك وجه الله).", "page": 99, "id": "unit-09__lesson-03__b12", "inline": [{"t": "text", "s": "6- "}, {"t": "emphasis", "s": "الإخلاص", "role": "emphasis"}, {"t": "text", "s": ": ألا يطلب بهذه الكلمة إلا وجه الله وحده، "}, {"t": "ayah", "s": "وَمَآ أُمِرُوٓاْ إِلَّا لِيَعۡبُدُواْ ٱللَّهَ مُخۡلِصِينَ لَهُ ٱلدِّينَ", "ayah": [], "verses": [{"n": 5, "text": "وَمَآ أُمِرُوٓاْ إِلَّا لِيَعۡبُدُواْ ٱللَّهَ مُخۡلِصِينَ لَهُ ٱلدِّينَ", "surah": 98, "surah_name": "البينة", "ref": "98:5", "ref_api": "https://api.quran.com/api/v4/verses/by_key/98:5"}], "surah": 98, "ref_api": "https://api.quran.com/api/v4/verses/by_key/98:5", "surah_name": "البينة", "ayah_canonical": 5, "match": "contained", "ref": "98:5"}, {"t": "text", "s": "، وقال رسول الله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(إن الله حرَّم على النار من قال: لا إله إلا الله يبتغي بذلك وجه الله)", "role": "emphasis"}, {"t": "text", "s": "."}], "list": {"type": "ordered", "marker": "6"}}, {"type": "paragraph", "md": "7- المحبة: وذلك بأن يحب قائُلها اللهَ ورسولَه ودينَ الإسلام والمسلمين القائمين بأوامر الله؛ الواقفين عند حدوده، وأن يبغض من خالف «لا إله إلا الله» وأتى بما يناقضها من شرك أو كفر.", "page": 99, "id": "unit-09__lesson-03__b13", "inline": [{"t": "text", "s": "7- "}, {"t": "emphasis", "s": "المحبة", "role": "emphasis"}, {"t": "text", "s": ": وذلك بأن يحب قائُلها اللهَ ورسولَه ودينَ الإسلام والمسلمين القائمين بأوامر الله؛ الواقفين عند حدوده، وأن يبغض من خالف "}, {"t": "quote", "s": "لا إله إلا الله"}, {"t": "text", "s": " وأتى بما يناقضها من شرك أو كفر."}], "list": {"type": "ordered", "marker": "7"}}, {"type": "paragraph", "md": "قال الله تعالى: ﴿وَمِنَ ٱلنَّاسِ مَن يَتَّخِذُ مِن دُونِ ٱللَّهِ أَندَادٗا يُحِبُّونَهُمۡ كَحُبِّ ٱللَّهِۖ وَٱلَّذِينَ ءَامَنُوٓاْ أَشَدُّ حُبّٗا لِّلَّهِۗ﴾، وقال رسول الله صلى الله عليه وسلم : (لا يؤمن أحدكم حتى أكون أحب إليه من ولده ووالده والناس أجمعين)، وقال النبي صلى الله عليه وسلم : (أوثق عرى الإيمان: الحب في الله والبغض في الله).", "page": 99, "id": "unit-09__lesson-03__b14", "inline": [{"t": "text", "s": "قال الله تعالى: "}, {"t": "ayah", "s": "وَمِنَ ٱلنَّاسِ مَن يَتَّخِذُ مِن دُونِ ٱللَّهِ أَندَادٗا يُحِبُّونَهُمۡ كَحُبِّ ٱللَّهِۖ وَٱلَّذِينَ ءَامَنُوٓاْ أَشَدُّ حُبّٗا لِّلَّهِۗ", "ayah": [], "verses": [{"n": 165, "text": "وَمِنَ ٱلنَّاسِ مَن يَتَّخِذُ مِن دُونِ ٱللَّهِ أَندَادٗا يُحِبُّونَهُمۡ كَحُبِّ ٱللَّهِۖ وَٱلَّذِينَ ءَامَنُوٓاْ أَشَدُّ حُبّٗا لِّلَّهِۗ", "surah": 2, "surah_name": "البقرة", "ref": "2:165", "ref_api": "https://api.quran.com/api/v4/verses/by_key/2:165"}], "surah": 2, "ref_api": "https://api.quran.com/api/v4/verses/by_key/2:165", "surah_name": "البقرة", "ayah_canonical": 165, "match": "contained", "ref": "2:165"}, {"t": "text", "s": "، وقال رسول الله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(لا يؤمن أحدكم حتى أكون أحب إليه من ولده ووالده والناس أجمعين)", "role": "emphasis"}, {"t": "text", "s": "، وقال النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(أوثق عرى الإيمان: الحب في الله والبغض في الله)", "role": "emphasis"}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "يقول الشيخ حافظ الحكمي ناظمًا هذه الشروط في منظزمته «سلم الوصول»:", "page": 99, "id": "unit-09__lesson-03__b15", "inline": [{"t": "text", "s": "يقول الشيخ حافظ الحكمي ناظمًا هذه الشروط في منظزمته "}, {"t": "quote", "s": "سلم الوصول"}, {"t": "text", "s": ":"}]}, {"type": "table", "rows": [["وبشروط سبعة قد قيدت", "", "وفي نصوص الوحي حقا وردت"], ["فإنه لم ينتفع قائلها", "", "بالنطق إلا حيث يستكملها"], ["العلم واليقين والقبول", "", "والانقياد فادر ما أقول"], ["والصدق والإخلاص والمحبة", "", "وفقك الله لما أحبه"]], "html": "<table dir=\"rtl\"><tr><td>وبشروط سبعة قد قيدت</td><td></td><td>وفي نصوص الوحي حقا وردت</td></tr><tr><td>فإنه لم ينتفع قائلها</td><td></td><td>بالنطق إلا حيث يستكملها</td></tr><tr><td>العلم واليقين والقبول</td><td></td><td>والانقياد فادر ما أقول</td></tr><tr><td>والصدق والإخلاص والمحبة</td><td></td><td>وفقك الله لما أحبه</td></tr></table>", "page": 99, "id": "unit-09__lesson-03__b16", "subtype": "poem", "abyat": [{"sadr": "وبشروط سبعة قد قيدت", "ajuz": "وفي نصوص الوحي حقا وردت"}, {"sadr": "فإنه لم ينتفع قائلها", "ajuz": "بالنطق إلا حيث يستكملها"}, {"sadr": "العلم واليقين والقبول", "ajuz": "والانقياد فادر ما أقول"}, {"sadr": "والصدق والإخلاص والمحبة", "ajuz": "وفقك الله لما أحبه"}]}, {"type": "paragraph", "md": "ملاحظة (1): أغلب عوام المسلمين يحقق هذه الشروط ولا يستطيع صياغتها بلسانه، وهذا لا يضره بشيء.", "page": 99, "id": "unit-09__lesson-03__b17", "inline": [{"t": "emphasis", "s": "ملاحظة (1)", "role": "emphasis"}, {"t": "text", "s": ": أغلب عوام المسلمين يحقق هذه الشروط ولا يستطيع صياغتها بلسانه، وهذا لا يضره بشيء."}]}, {"type": "paragraph", "md": "ملاحظة (2): هذه الشروط يجب تحققها ليكون الشخص مسلما حقا ظاهرا وباطنا، وأما لنحكم على شخص بالإسلام؛ فغير مطلوب أن نتحقق من استيفائه هذه الشروط؛ بل لنا الظاهر والله يتولى السرائر.", "page": 99, "id": "unit-09__lesson-03__b18", "inline": [{"t": "emphasis", "s": "ملاحظة (2)", "role": "emphasis"}, {"t": "text", "s": ": هذه الشروط يجب تحققها ليكون الشخص مسلما حقا ظاهرا وباطنا، وأما لنحكم على شخص بالإسلام؛ فغير مطلوب أن نتحقق من استيفائه هذه الشروط؛ بل لنا الظاهر والله يتولى السرائر."}]}, {"type": "heading", "level": 3, "text": "التقويم والأسئلة الإثرائية:", "page": 99, "id": "unit-09__lesson-03__b19", "role": "assessment"}, {"type": "paragraph", "md": "1- عدد شروط كلمة التوحيد السبعة؛ شارحًا اثنين منها شرحًا وافيًا.", "page": 99, "id": "unit-09__lesson-03__b20", "item_role": "question", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- هل تعداد شروط كلمة التوحيد ركن في الإيمان؟ أم يكفي للمرء أن يعمل بمقتضاها ولو لم يعددها.", "page": 99, "id": "unit-09__lesson-03__b21", "item_role": "question", "list": {"type": "ordered", "marker": "2"}}, {"type": "heading", "level": 3, "text": "نشاط بحثي علمي", "page": 99, "id": "unit-09__lesson-03__b22", "role": "activity"}, {"type": "paragraph", "md": "نطلع على كتاب «شروط لا إله إلا الله» للشيخ عبد المنعم مصطفى حليمة.. ونذكر أهم فوائده!", "page": 99, "id": "unit-09__lesson-03__b23", "inline": [{"t": "text", "s": "نطلع على كتاب "}, {"t": "quote", "s": "شروط لا إله إلا الله"}, {"t": "text", "s": " للشيخ عبد المنعم مصطفى حليمة.. ونذكر أهم فوائده!"}], "item_role": "activity_step"}]' WHERE id='unit-09__lesson-03';
INSERT INTO manhaj_lessons (id,unit_id,ord,title,subject,duration_min,hadith_count,quran_count,blocks) VALUES ('unit-09__lesson-04','unit-09',4,'أسباب الحدث «نواقض الوضوء»','الفقه',NULL,0,0,'');
UPDATE manhaj_lessons SET blocks = blocks || '[{"type": "heading", "level": 3, "text": "أهداف الدرس:", "page": 100, "id": "unit-09__lesson-04__b01", "role": "objectives"}, {"type": "paragraph", "md": "بيان الأسباب التي تؤدي إلى الحدث فيجب معها الوضوء.", "page": 100, "id": "unit-09__lesson-04__b02"}, {"type": "paragraph", "md": "ذكر الأمور التي يستحب لها الوضوء.", "page": 100, "id": "unit-09__lesson-04__b03"}, {"type": "heading", "level": 3, "text": "أسباب الحدث خمسة، وهي التي يجب لأجلها الوضوء لتصح العبادة:", "page": 100, "id": "unit-09__lesson-04__b04", "role": "section"}, {"type": "paragraph", "md": "1- خروج البَوْل أو المَذي أو الوَدي من القُبل، أو الغائط أو الريح من الدبر. والمذي هو: ماء أبيض رقيق يخرج عند اللذة المعتادة ولا تفتر الشهوة بعده، والودي: ماء أبيض كدر ثخين، يشبه المني في الثخانة ويخالفه في الكدورة ولا رائحة له، ويخرج عقب البول عادةً، ويسيل بغير تدفق خلافًا للمني.", "page": 100, "id": "unit-09__lesson-04__b05", "inline": [{"t": "emphasis", "s": "1- خروج البَوْل أو المَذي أو الوَدي من القُبل، أو الغائط أو الريح من الدبر", "role": "emphasis"}, {"t": "text", "s": ". والمذي هو: ماء أبيض رقيق يخرج عند اللذة المعتادة ولا تفتر الشهوة بعده، والودي: ماء أبيض كدر ثخين، يشبه المني في الثخانة ويخالفه في الكدورة ولا رائحة له، ويخرج عقب البول عادةً، ويسيل بغير تدفق خلافًا للمني."}], "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- زوال العقل: بأن ينامَ غير مُتَمَكِّنٍ بمَقْعَدَتِهِ، وشرطُهُ: الاستغراق، ويلحَقُ به الجنون والإغماء والسُّكْر قياسًا؛ لأنَّ زوال العقل مظنة للحدث، وفي الحديث الصحيح: (العين وِكَاء السَّهْ، فمن نام فليتوضأ)، و«السه»: الدبر، والوكاء: ما يربط به الكيس ونحوه لئلا يتدفق ما فيه؛ فإذا نامت العينان خرج الريح بغير شعور المرء؛ فالنوم الناقض للوضوء هو النوم العميق الذي يسترخي به الدبر، فتخرج الريح بلا شعور.", "page": 100, "id": "unit-09__lesson-04__b06", "inline": [{"t": "emphasis", "s": "2- زوال العقل", "role": "emphasis"}, {"t": "text", "s": ": بأن ينامَ غير مُتَمَكِّنٍ بمَقْعَدَتِهِ، وشرطُهُ: الاستغراق، ويلحَقُ به الجنون والإغماء والسُّكْر قياسًا؛ لأنَّ زوال العقل مظنة للحدث، وفي الحديث الصحيح: "}, {"t": "emphasis", "s": "(العين وِكَاء السَّهْ، فمن نام فليتوضأ)", "role": "emphasis"}, {"t": "text", "s": "، و"}, {"t": "quote", "s": "السه"}, {"t": "text", "s": ": الدبر، والوكاء: ما يربط به الكيس ونحوه لئلا يتدفق ما فيه؛ فإذا نامت العينان خرج الريح بغير شعور المرء؛ فالنوم الناقض للوضوء هو النوم العميق الذي يسترخي به الدبر، فتخرج الريح بلا شعور."}], "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "3- مَسُّ ذكر الرجل أو فرج المرأة بباطن اليد، وقد صَحَّ حديث بُسرة بنت صفوان رضي الله عنها : (مَن مسَّ ذَكَرَه فَلَا يُصَلِّي حَتَّى يَتَوَضَّأَ)، وكذلك مس حلقة الدبر قياسا، وإن لمسه غيره فلا ينتقض وضوء الملموس.", "page": 100, "id": "unit-09__lesson-04__b07", "inline": [{"t": "emphasis", "s": "3- مَسُّ ذكر الرجل أو فرج المرأة بباطن اليد", "role": "emphasis"}, {"t": "text", "s": "، وقد صَحَّ حديث بُسرة بنت صفوان "}, {"t": "honorific", "s": "رضي الله عنها"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(مَن مسَّ ذَكَرَه فَلَا يُصَلِّي حَتَّى يَتَوَضَّأَ)", "role": "emphasis"}, {"t": "text", "s": "، وكذلك مس حلقة الدبر قياسا، وإن لمسه غيره فلا ينتقض وضوء الملموس."}], "list": {"type": "ordered", "marker": "3"}}, {"type": "paragraph", "md": "4- أَكْلُ لحم الإبل -وهو القديم من مذهب الشافعي-، لحديث مسلم: (توضأ من لحوم الإبل).", "page": 100, "id": "unit-09__lesson-04__b08", "inline": [{"t": "emphasis", "s": "4- أَكْلُ لحم الإبل", "role": "emphasis"}, {"t": "text", "s": " -وهو القديم من مذهب الشافعي-، لحديث مسلم: "}, {"t": "emphasis", "s": "(توضأ من لحوم الإبل)", "role": "emphasis"}, {"t": "text", "s": "."}], "list": {"type": "ordered", "marker": "4"}}, {"type": "paragraph", "md": "5- خروج دم الاستحاضة للمرأة المستحاضة؛ فيجب أن تتوضأ لكل صلاة في هذه الحالة.", "page": 100, "id": "unit-09__lesson-04__b09", "inline": [{"t": "emphasis", "s": "5- خروج دم الاستحاضة للمرأة المستحاضة", "role": "emphasis"}, {"t": "text", "s": "؛ فيجب أن تتوضأ لكل صلاة في هذه الحالة."}], "list": {"type": "ordered", "marker": "5"}}, {"type": "paragraph", "md": "فائدة: كل ما يوجب الحدث الأكبر (كالجنابة والحيض والنفاس) فإنه يوجب الحدث الأصغر كذلك.", "page": 100, "id": "unit-09__lesson-04__b10", "inline": [{"t": "emphasis", "s": "فائدة", "role": "emphasis"}, {"t": "text", "s": ": كل ما يوجب الحدث الأكبر "}, {"t": "emphasis", "s": "(كالجنابة والحيض والنفاس)", "role": "emphasis"}, {"t": "text", "s": " فإنه يوجب الحدث الأصغر كذلك."}]}, {"type": "heading", "level": 3, "text": "ويُسْتَحَبُّ الوضوءُ لأمورٍ عِدّةٍ، منها:", "page": 100, "id": "unit-09__lesson-04__b11", "role": "section"}, {"type": "paragraph", "md": "1- عند ذكر الله تعالى؛ لحديث المهاجر بن قنفذ أنَّهُ أتى النَّبيَّ صلى الله عليه وسلم وَهوَ يبولُ فسلَّمَ عليهِ فَلَمْ يَرُدَّ عَلَيْهِ حتَّى تَوضَّأ ثمَّ اعتَذَرَ إليهِ فَقَالَ: (إنِّي كَرِهْتُ أن أذكرَ اللَّهَ إلَّا علَى طُهْرٍ). أو قالَ: (علَى طَهارةٍ).", "page": 100, "id": "unit-09__lesson-04__b12", "inline": [{"t": "emphasis", "s": "1- عند ذكر الله تعالى", "role": "emphasis"}, {"t": "text", "s": "؛ لحديث المهاجر بن قنفذ أنَّهُ أتى النَّبيَّ "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " وَهوَ يبولُ فسلَّمَ عليهِ فَلَمْ يَرُدَّ عَلَيْهِ حتَّى تَوضَّأ ثمَّ اعتَذَرَ إليهِ فَقَالَ: "}, {"t": "emphasis", "s": "(إنِّي كَرِهْتُ أن أذكرَ اللَّهَ إلَّا علَى طُهْرٍ)", "role": "emphasis"}, {"t": "text", "s": ". أو قالَ: "}, {"t": "emphasis", "s": "(علَى طَهارةٍ)", "role": "emphasis"}, {"t": "text", "s": "."}], "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- الجُنُب إذا أرادَ النَّوْمَ أو الأَكْلَ أو مُعَاوَدَةَ الجِماع: لحديث عائشة رضي الله عنها في الصحيحَيْن: كَانَ رَسُولُ اللهِ صلى الله عليه وسلم إِذَا كَانَ جُنُبًا فَأَرَادَ أَنْ يَأْكُلَ أَوْ يَنَامَ تَوَضَّأَ وُضُوءَهُ لِلصَّلَاةِ.", "page": 100, "id": "unit-09__lesson-04__b13", "inline": [{"t": "emphasis", "s": "2- الجُنُب إذا أرادَ النَّوْمَ أو الأَكْلَ أو مُعَاوَدَةَ الجِماع", "role": "emphasis"}, {"t": "text", "s": ": لحديث عائشة "}, {"t": "honorific", "s": "رضي الله عنها"}, {"t": "text", "s": " في الصحيحَيْن: كَانَ رَسُولُ اللهِ "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " إِذَا كَانَ جُنُبًا فَأَرَادَ أَنْ يَأْكُلَ أَوْ يَنَامَ تَوَضَّأَ وُضُوءَهُ لِلصَّلَاةِ."}], "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "3- ويُسْتَحَبُّ الوضوء قبل الاغتسال، لحديث عائشة رضي الله عنها في البُخاريِّ: (أنَّ النبيَّ صلى الله عليه وسلم كانَ إذَا اغْتَسَلَ مِنَ الجَنَابَةِ، بَدَأَ فَغَسَلَ يَدَيْهِ، ثُمَّ يَتَوَضَّأُ كما يَتَوَضَّأُ لِلصَّلَاةِ، ثُمَّ يُدْخِلُ أصَابِعَهُ في المَاءِ، فيُخَلِّلُ بهَا أُصُولَ شَعَرِهِ، ثُمَّ يَصُبُّ علَى رَأْسِهِ ثَلَاثَ غُرَفٍ بيَدَيْهِ، ثُمَّ يُفِيضُ المَاءَ علَى جِلْدِهِ كُلِّهِ).", "page": 101, "id": "unit-09__lesson-04__b14", "inline": [{"t": "emphasis", "s": "3- ويُسْتَحَبُّ الوضوء قبل الاغتسال", "role": "emphasis"}, {"t": "text", "s": "، لحديث عائشة "}, {"t": "honorific", "s": "رضي الله عنها"}, {"t": "text", "s": " في البُخاريِّ: "}, {"t": "emphasis", "s": "(أنَّ النبيَّ", "role": "emphasis"}, {"t": "text", "s": " "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " "}, {"t": "emphasis", "s": "كانَ إذَا اغْتَسَلَ مِنَ الجَنَابَةِ، بَدَأَ فَغَسَلَ يَدَيْهِ، ثُمَّ يَتَوَضَّأُ كما يَتَوَضَّأُ لِلصَّلَاةِ، ثُمَّ يُدْخِلُ أصَابِعَهُ في المَاءِ، فيُخَلِّلُ بهَا أُصُولَ شَعَرِهِ، ثُمَّ يَصُبُّ علَى رَأْسِهِ ثَلَاثَ غُرَفٍ بيَدَيْهِ، ثُمَّ يُفِيضُ المَاءَ علَى جِلْدِهِ كُلِّهِ)", "role": "emphasis"}, {"t": "text", "s": "."}], "list": {"type": "ordered", "marker": "3"}}, {"type": "paragraph", "md": "4- لِمَنْ حَمَلَ أو غَسَّلَ مَيِّتًا؛ لقول ابن عمر: «كنا نغسل الميت، فمنا من يغتسل، ومنا من لا يغتسل».", "page": 101, "id": "unit-09__lesson-04__b15", "inline": [{"t": "emphasis", "s": "4- لِمَنْ حَمَلَ أو غَسَّلَ مَيِّتًا", "role": "emphasis"}, {"t": "text", "s": "؛ لقول ابن عمر: "}, {"t": "quote", "s": "كنا نغسل الميت، فمنا من يغتسل، ومنا من لا يغتسل"}, {"t": "text", "s": "."}], "list": {"type": "ordered", "marker": "4"}}, {"type": "paragraph", "md": "5- لكُلِّ صلاة: لِمَا أخرجه مسلم من حديث بُرَيْدَة رضي الله عنه (أَنَّ النَّبِيَّ صلى الله عليه وسلم كَانَ يَتَوَضَّأُ لِكُلِّ صَلَاةٍ).", "page": 101, "id": "unit-09__lesson-04__b16", "inline": [{"t": "emphasis", "s": "5- لكُلِّ صلاة", "role": "emphasis"}, {"t": "text", "s": ": لِمَا أخرجه مسلم من حديث بُرَيْدَة "}, {"t": "honorific", "s": "رضي الله عنه"}, {"t": "text", "s": " "}, {"t": "emphasis", "s": "(أَنَّ النَّبِيَّ", "role": "emphasis"}, {"t": "text", "s": " "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " "}, {"t": "emphasis", "s": "كَانَ يَتَوَضَّأُ لِكُلِّ صَلَاةٍ)", "role": "emphasis"}, {"t": "text", "s": "."}], "list": {"type": "ordered", "marker": "5"}}, {"type": "heading", "level": 3, "text": "ما يحرم على المحدث:", "page": 101, "id": "unit-09__lesson-04__b17", "role": "section"}, {"type": "paragraph", "md": "1- فعل الصلاة: لقوله صلى الله عليه وسلم : (لا يقبل الله صلاة أحدكم إذا أحدث حتى يتوضأ).", "page": 101, "id": "unit-09__lesson-04__b18", "inline": [{"t": "emphasis", "s": "1- فعل الصلاة:", "role": "emphasis"}, {"t": "text", "s": " لقوله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(لا يقبل الله صلاة أحدكم إذا أحدث حتى يتوضأ)", "role": "emphasis"}, {"t": "text", "s": "."}], "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- الطواف بالبيت: لما جاء في الحديث أن الطواف صلاة؛ فيلحقها في وجوب الطهارة.", "page": 101, "id": "unit-09__lesson-04__b19", "inline": [{"t": "emphasis", "s": "2- الطواف بالبيت", "role": "emphasis"}, {"t": "text", "s": ": لما جاء في الحديث أن الطواف صلاة؛ فيلحقها في وجوب الطهارة."}], "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "3- لمس المصحف: وهو مذهب الأئمة الأربعة، واختيار ابن تيمية، ولا بأس بقراءته من غير وضوء.", "page": 101, "id": "unit-09__lesson-04__b20", "inline": [{"t": "emphasis", "s": "3- لمس المصحف", "role": "emphasis"}, {"t": "text", "s": ": وهو مذهب الأئمة الأربعة، واختيار ابن تيمية، ولا بأس بقراءته من غير وضوء."}], "list": {"type": "ordered", "marker": "3"}}, {"type": "heading", "level": 3, "text": "مسائل في الشك واليقين في الطهارة:", "page": 101, "id": "unit-09__lesson-04__b21", "role": "benefits"}, {"type": "paragraph", "md": "إذا استيقن الطهارة بالوضوء أو الغسل الأكبر، وشك في الحدث بعده: بنى على اليقين استصحابًا للطهارة، وعملًا بالأصل؛ لا فرق بين أن يغلب على ظنه أحدهما، أو يتساوى الأمران عنده.", "page": 101, "id": "unit-09__lesson-04__b22"}, {"type": "paragraph", "md": "من تيقن الوضوء وشك في الحدث: فالأصل بقاء ما كان على ما كان، وأنه لا ينتقل عن الأصل الذي هو بقاء الطهارة إلا بيقين، وعليه فلا يجب الوضوء على من شك في الحدث.", "page": 101, "id": "unit-09__lesson-04__b23"}, {"type": "paragraph", "md": "لحديث صحيح مسلم أنه: (شُكِيَ إلى رسول الله صلى الله عليه وسلم الرجل الذي يخيل إليه أنه يجد الشيء في الصلاة، فقال: لا ينفتل أو لا ينصرف حتى يسمع صوتًا أو يجد ريحًا).", "page": 101, "id": "unit-09__lesson-04__b24", "inline": [{"t": "text", "s": "لحديث صحيح مسلم أنه: "}, {"t": "emphasis", "s": "(شُكِيَ إلى رسول الله", "role": "emphasis"}, {"t": "text", "s": " "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " "}, {"t": "emphasis", "s": "الرجل الذي يخيل إليه أنه يجد الشيء في الصلاة، فقال: لا ينفتل أو لا ينصرف حتى يسمع صوتًا أو يجد ريحًا)", "role": "emphasis"}, {"t": "text", "s": "."}]}, {"type": "heading", "level": 3, "text": "التقويم والأسئلة:", "page": 101, "id": "unit-09__lesson-04__b25", "role": "assessment"}, {"type": "paragraph", "md": "عدد اثنين من موجبات الحدث التي يجب الوضوء معها.", "page": 101, "id": "unit-09__lesson-04__b26", "item_role": "question"}, {"type": "paragraph", "md": "اذكر أمرين يستحب لهما الوضوء.", "page": 101, "id": "unit-09__lesson-04__b27", "item_role": "question"}, {"type": "paragraph", "md": "ماذا يفعل من شك في وضوئه: بين الحالات المتعلقة بذلك.", "page": 101, "id": "unit-09__lesson-04__b28", "item_role": "question"}, {"type": "heading", "level": 3, "text": "نشاط عملي", "page": 101, "id": "unit-09__lesson-04__b29", "role": "activity"}, {"type": "paragraph", "md": "1- حاء في حديث صحيح أن الإبل خُلقت من الشياطين؛ بين معنى ذلك واشرحه.", "page": 101, "id": "unit-09__lesson-04__b30", "item_role": "activity_step", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- تنناقش: ما هي فائدة معرفة أحكام الوضوء، وهل تعملها ضروري فعلا؟ وضح ذلك.", "page": 101, "id": "unit-09__lesson-04__b31", "item_role": "activity_step", "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "3- بعد أن تعلمنا أحكام الوضوء؛ يُطلب منكَ تعريف هذه الأحكام لخمسة من معارفك، مع ذكر ٍأسمائهم لشيخك، وتصحيح ما تعرفه من أخطائهم، وما جهلته من المسائل فاسال عنه شيخك.", "page": 101, "id": "unit-09__lesson-04__b32", "item_role": "activity_step", "list": {"type": "ordered", "marker": "3"}}]' WHERE id='unit-09__lesson-04';
INSERT INTO manhaj_lessons (id,unit_id,ord,title,subject,duration_min,hadith_count,quran_count,blocks) VALUES ('unit-09__lesson-05','unit-09',5,'علو الهمة','الأخلاق والآداب',NULL,0,3,'');
UPDATE manhaj_lessons SET blocks = blocks || '[{"type": "heading", "level": 3, "text": "أهداف الدرس:", "page": 102, "id": "unit-09__lesson-05__b01", "role": "objectives"}, {"type": "paragraph", "md": "أن يتعرف على معنى خلق علو الهمة الذي سبقَ فيه الصالحون غيرَهم.", "page": 102, "id": "unit-09__lesson-05__b02"}, {"type": "paragraph", "md": "أن يتمثل هذا الخلق في حياته ويتحلى به في كل أوقاته متأسيا بهدي النبي صلى الله عليه وسلم .", "page": 102, "id": "unit-09__lesson-05__b03", "inline": [{"t": "text", "s": "أن يتمثل هذا الخلق في حياته ويتحلى به في كل أوقاته متأسيا بهدي النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " ."}]}, {"type": "heading", "level": 3, "text": "(اللهم إني أعوذ بك من العجز والكسل!)", "page": 102, "id": "unit-09__lesson-05__b04", "role": "section"}, {"type": "paragraph", "md": "لقد كان جيل الصحابة رضي الله عنهم على درجةٍ عالية من الهمة والنشاط، اقتضت من النبي صلى الله عليه وسلم أن يدعوَهم في كثير من المواقف إلى تقليل هذا النشاط الزائد، والعودة إلى التوازن قائلًا لهم: (اكلَفُوا من الأعمال ما تطيقون) ويُجيب أكثر من ذلك: (يا رسول الله! إني أُطيق أكثر من ذلك).", "page": 102, "id": "unit-09__lesson-05__b05", "inline": [{"t": "text", "s": "لقد كان جيل الصحابة "}, {"t": "honorific", "s": "رضي الله عنهم"}, {"t": "text", "s": " على درجةٍ عالية من الهمة والنشاط، اقتضت من النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " أن يدعوَهم في كثير من المواقف إلى تقليل هذا النشاط الزائد، والعودة إلى التوازن قائلًا لهم: "}, {"t": "emphasis", "s": "(اكلَفُوا من الأعمال ما تطيقون)", "role": "emphasis"}, {"t": "text", "s": " ويُجيب أكثر من ذلك: "}, {"t": "emphasis", "s": "(يا رسول الله! إني أُطيق أكثر من ذلك)", "role": "emphasis"}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "وحين ضعفت العزائم، وفترت الهمم؛ صار الواحد من الناس حين يُطالب بأداء بعض الواجبات يكون جوابه: لا أطيق ذلك! فأصبحنا بحاجة كبيرة للاستعاذة بالله من هذا الحال: (اللهم إني أعوذ بك من العجز والكسل)، والرجوع لقوله تعالى: ﴿۞وَسَارِعُوٓاْ﴾، ﴿سَابِقُوٓاْ﴾، ﴿يَٰيَحۡيَىٰ خُذِ ٱلۡكِتَٰبَ بِقُوَّةٖۖ﴾.", "page": 102, "id": "unit-09__lesson-05__b06", "inline": [{"t": "text", "s": "وحين ضعفت العزائم، وفترت الهمم؛ صار الواحد من الناس حين يُطالب بأداء بعض الواجبات يكون جوابه: لا أطيق ذلك! فأصبحنا بحاجة كبيرة للاستعاذة بالله من هذا الحال: "}, {"t": "emphasis", "s": "(اللهم إني أعوذ بك من العجز والكسل)", "role": "emphasis"}, {"t": "text", "s": "، والرجوع لقوله تعالى: "}, {"t": "ayah", "s": "۞وَسَارِعُوٓاْ", "ayah": [], "verses": [{"n": 133, "text": "۞وَسَارِعُوٓاْ", "surah": 3, "surah_name": "آل عمران", "ref": "3:133", "ref_api": "https://api.quran.com/api/v4/verses/by_key/3:133"}], "surah": 3, "ref_api": "https://api.quran.com/api/v4/verses/by_key/3:133", "surah_name": "آل عمران", "ayah_canonical": 133, "match": "contained", "ref": "3:133"}, {"t": "text", "s": "، "}, {"t": "ayah", "s": "سَابِقُوٓاْ", "ayah": [], "verses": [], "surah": null, "ref_api": null}, {"t": "text", "s": "، "}, {"t": "ayah", "s": "يَٰيَحۡيَىٰ خُذِ ٱلۡكِتَٰبَ بِقُوَّةٖۖ", "ayah": [], "verses": [{"n": 12, "text": "يَٰيَحۡيَىٰ خُذِ ٱلۡكِتَٰبَ بِقُوَّةٖۖ", "surah": 19, "surah_name": "مريم", "ref": "19:12", "ref_api": "https://api.quran.com/api/v4/verses/by_key/19:12"}], "surah": 19, "ref_api": "https://api.quran.com/api/v4/verses/by_key/19:12", "surah_name": "مريم", "ayah_canonical": 12, "match": "contained", "ref": "19:12"}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "ومن أدلة علو الهمة ما جاء في قوله صلى الله عليه وسلم أن أصدق الأسماء (حارث وهمام).؛ ليكون المرء صاحب همٍّ في الأمور كلها، فيسعى ويحرث ويكتسب، فكلا الاسمين يدلان على الكدح والعمل.", "page": 102, "id": "unit-09__lesson-05__b07", "inline": [{"t": "text", "s": "ومن أدلة علو الهمة ما جاء في قوله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " أن أصدق الأسماء "}, {"t": "emphasis", "s": "(حارث وهمام)", "role": "emphasis"}, {"t": "text", "s": ".؛ ليكون المرء صاحب همٍّ في الأمور كلها، فيسعى ويحرث ويكتسب، فكلا الاسمين يدلان على الكدح والعمل."}]}, {"type": "paragraph", "md": "بقول سيد قطب: «الصف الذي يتخلله الضعاف المسترخون لا يصمد؛ لأنهم يخذلونه في ساعة الشدة»؛ فلذلك لا بدَّ أن تكون الهمة صفة أصيلة في أخلاق الشباب المسلم؛ ليكونوا أقدر على الثبات والصمود.", "page": 102, "id": "unit-09__lesson-05__b08", "inline": [{"t": "text", "s": "بقول سيد قطب: "}, {"t": "quote", "s": "الصف الذي يتخلله الضعاف المسترخون لا يصمد؛ لأنهم يخذلونه في ساعة الشدة"}, {"t": "text", "s": "؛ فلذلك لا بدَّ أن تكون الهمة صفة أصيلة في أخلاق الشباب المسلم؛ ليكونوا أقدر على الثبات والصمود."}]}, {"type": "paragraph", "md": "وتأمل في زيد بن ثابت رضي الله عنه الذي كلفه النبي صلى الله عليه وسلم بتعلم لغة اليهود وهو ابن أحد عشر سنة فأتقنها في نصف شهر فقط، وهذه الطاقة العالية في العلم لا تأتي إلا لصاحب همة ونشاط كبير.", "page": 102, "id": "unit-09__lesson-05__b09", "inline": [{"t": "text", "s": "وتأمل في زيد بن ثابت "}, {"t": "honorific", "s": "رضي الله عنه"}, {"t": "text", "s": " الذي كلفه النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " بتعلم لغة اليهود وهو ابن أحد عشر سنة فأتقنها في نصف شهر فقط، وهذه الطاقة العالية في العلم لا تأتي إلا لصاحب همة ونشاط كبير."}]}, {"type": "heading", "level": 3, "text": "التقويم والأسئلة:", "page": 102, "id": "unit-09__lesson-05__b10", "role": "assessment"}, {"type": "paragraph", "md": "ما معنى خلق الهمة العالية؟ ولماذا نتخلق به؟ واذكر دليلين عليه من الكتاب والسنة؟", "page": 102, "id": "unit-09__lesson-05__b11", "item_role": "question"}, {"type": "heading", "level": 3, "text": "نشاط تحليلي وبحثي", "page": 102, "id": "unit-09__lesson-05__b12", "role": "activity"}, {"type": "paragraph", "md": "1- ضعف الهمة صفة مميزة للمنافقين.. ارجع إلى تفسير آيات النفاق لتذكر لنا الربط بين النفاقِ والكسل!", "page": 102, "id": "unit-09__lesson-05__b13", "item_role": "activity_step", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- ارجع إلى كتاب «صفحات من صبر العلماء» لأبي غدة، واسترخج قصة أحد العلماء في علو الهمة في العلم", "page": 102, "id": "unit-09__lesson-05__b14", "inline": [{"t": "text", "s": "2- ارجع إلى كتاب "}, {"t": "quote", "s": "صفحات من صبر العلماء"}, {"t": "text", "s": " لأبي غدة، واسترخج قصة أحد العلماء في علو الهمة في العلم"}], "item_role": "activity_step", "list": {"type": "ordered", "marker": "2"}}]' WHERE id='unit-09__lesson-05';
INSERT INTO manhaj_lessons (id,unit_id,ord,title,subject,duration_min,hadith_count,quran_count,blocks) VALUES ('unit-10__lesson-01','unit-10',1,'سورة قريش','القرآن والتفسير',NULL,0,9,'');
UPDATE manhaj_lessons SET blocks = blocks || '[{"type": "paragraph", "md": "بِسۡمِ ٱللَّهِ ٱلرَّحۡمَٰنِ ٱلرَّحِيمِ: ﴿لِإِيلَٰفِ قُرَيۡشٍ ۝١ إِۦلَٰفِهِمۡ رِحۡلَةَ ٱلشِّتَآءِ وَٱلصَّيۡفِ ۝٢ فَلۡيَعۡبُدُواْ رَبَّ هَٰذَا ٱلۡبَيۡتِ ۝٣ ٱلَّذِيٓ أَطۡعَمَهُم مِّن جُوعٖ وَءَامَنَهُم مِّنۡ خَوۡفِۭ ۝٤﴾", "page": 102, "id": "unit-10__lesson-01__b01", "inline": [{"t": "text", "s": "بِسۡمِ ٱللَّهِ ٱلرَّحۡمَٰنِ ٱلرَّحِيمِ: "}, {"t": "ayah", "s": "لِإِيلَٰفِ قُرَيۡشٍ ۝١ إِۦلَٰفِهِمۡ رِحۡلَةَ ٱلشِّتَآءِ وَٱلصَّيۡفِ ۝٢ فَلۡيَعۡبُدُواْ رَبَّ هَٰذَا ٱلۡبَيۡتِ ۝٣ ٱلَّذِيٓ أَطۡعَمَهُم مِّن جُوعٖ وَءَامَنَهُم مِّنۡ خَوۡفِۭ ۝٤", "ayah": [1, 2, 3, 4], "verses": [{"n": 1, "text": "لِإِيلَٰفِ قُرَيۡشٍ", "surah": 106, "ref_api": "https://api.quran.com/api/v4/verses/by_key/106:1", "surah_name": "قريش", "ayah_canonical": 1, "match": "exact", "ref": "106:1"}, {"n": 2, "text": "إِۦلَٰفِهِمۡ رِحۡلَةَ ٱلشِّتَآءِ وَٱلصَّيۡفِ", "surah": 106, "ref_api": "https://api.quran.com/api/v4/verses/by_key/106:2", "surah_name": "قريش", "ayah_canonical": 2, "match": "exact", "ref": "106:2"}, {"n": 3, "text": "فَلۡيَعۡبُدُواْ رَبَّ هَٰذَا ٱلۡبَيۡتِ", "surah": 106, "ref_api": "https://api.quran.com/api/v4/verses/by_key/106:3", "surah_name": "قريش", "ayah_canonical": 3, "match": "exact", "ref": "106:3"}, {"n": 4, "text": "ٱلَّذِيٓ أَطۡعَمَهُم مِّن جُوعٖ وَءَامَنَهُم مِّنۡ خَوۡفِۭ", "surah": 106, "ref_api": "https://api.quran.com/api/v4/verses/by_key/106:4", "surah_name": "قريش", "ayah_canonical": 4, "match": "exact", "ref": "106:4"}], "surah": null, "ref_api": null}]}, {"type": "heading", "level": 3, "text": "أهداف الدرس:", "page": 102, "id": "unit-10__lesson-01__b02", "role": "objectives"}, {"type": "paragraph", "md": "معرفة مقاصد وموضوعات سورة قريش.", "page": 102, "id": "unit-10__lesson-01__b03"}, {"type": "paragraph", "md": "معرفة الألفاظ الغريبة والواردة في سورة الماعون، وإدراك المعنى الإجمالي للسورة.", "page": 102, "id": "unit-10__lesson-01__b04"}, {"type": "paragraph", "md": "معرفة الفوائد العلمية والتربوية لسورة الماعون.", "page": 102, "id": "unit-10__lesson-01__b05"}, {"type": "paragraph", "md": "حفظ السورة بضبط وإتقان.", "page": 102, "id": "unit-10__lesson-01__b06"}, {"type": "heading", "level": 3, "text": "مقصد السورة، وأهم الموضوعات التي اشتملت عليها:", "page": 102, "id": "unit-10__lesson-01__b07", "role": "main_themes"}, {"type": "paragraph", "md": "أما مقصدها، فهو: تذكير أهل مكة بجانب من نعم الله تعالى عليهم؛ حتى يؤمنوا بالله شكرًا لهذه النعمة.", "page": 102, "id": "unit-10__lesson-01__b08", "inline": [{"t": "emphasis", "s": "أما مقصدها، فهو:", "role": "emphasis"}, {"t": "text", "s": " تذكير أهل مكة بجانب من نعم الله تعالى عليهم؛ حتى يؤمنوا بالله شكرًا لهذه النعمة."}]}, {"type": "paragraph", "md": "وموضوعاتها ثلاثة: 1- ذكر المنة على قريش، بأن مكن اللهُ لهم التجارة برحلتي الشتاء والصيف.", "page": 102, "id": "unit-10__lesson-01__b09", "inline": [{"t": "emphasis", "s": "وموضوعاتها ثلاثة", "role": "emphasis"}, {"t": "text", "s": ": 1- ذكر المنة على قريش، بأن مكن اللهُ لهم التجارة برحلتي الشتاء والصيف."}]}, {"type": "paragraph", "md": "2- تحضيضهم على العبادة، وشكر نعمة الله عليهم.", "page": 102, "id": "unit-10__lesson-01__b10", "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "3- ذكر المنة عليهم بإطعامهم من جوع، وتأمينهم من المخاوف.", "page": 102, "id": "unit-10__lesson-01__b11", "list": {"type": "ordered", "marker": "3"}}, {"type": "heading", "level": 3, "text": "غريب الكلمات، والمعنى الإجمالي للسورة:", "page": 102, "id": "unit-10__lesson-01__b12", "role": "vocabulary"}, {"type": "paragraph", "md": "معنى ﴿لِإِيلَٰفِ﴾: أي: لِأُلفتهم واعتيادهم، والإيلاف: مصدر من آلفت الشيء؛ إذا لزمته وتعودت عليه.", "page": 102, "id": "unit-10__lesson-01__b13", "inline": [{"t": "text", "s": "معنى "}, {"t": "ayah", "s": "لِإِيلَٰفِ", "ayah": [], "verses": [], "surah": null, "ref_api": null}, {"t": "text", "s": ": أي: لِأُلفتهم واعتيادهم، والإيلاف: مصدر من آلفت الشيء؛ إذا لزمته وتعودت عليه."}]}, {"type": "paragraph", "md": "وأما المعنى الإجمالي؛ فقد افتتح الله تعالى هذه السورة الكريمة بذكر مِنَّة أخرى على قريش إثر ذكر نعمته عليهم بإهلاك عدوهم، وهي منة اجتماعهم واعتيادهم كل عام القيام برحلة في الشتاء إلى اليمن، ورحلة في الصيف إلى الشام للتجارة. ثم أرشدهم إلى شكر هذه النعمة العظيمة، فقال: فليعبدوا رب البيت الحرام، الذي أطعمهم من الجوع، وآمنهم من الخوف؛ فإنَّ من أنعم عليهم هو المستحق لأن يعبدوه.", "page": 102, "id": "unit-10__lesson-01__b14", "inline": [{"t": "emphasis", "s": "وأما المعنى الإجمالي", "role": "lemma"}, {"t": "text", "s": "؛ فقد افتتح الله تعالى هذه السورة الكريمة بذكر مِنَّة أخرى على قريش إثر ذكر نعمته عليهم بإهلاك عدوهم، وهي منة اجتماعهم واعتيادهم كل عام القيام برحلة في الشتاء إلى اليمن، ورحلة في الصيف إلى الشام للتجارة. ثم أرشدهم إلى شكر هذه النعمة العظيمة، فقال: فليعبدوا رب البيت الحرام، الذي أطعمهم من الجوع، وآمنهم من الخوف؛ فإنَّ من أنعم عليهم هو المستحق لأن يعبدوه."}]}, {"type": "heading", "level": 3, "text": "الفوائد التربوية:", "page": 102, "id": "unit-10__lesson-01__b15", "role": "benefits"}, {"type": "paragraph", "md": "1- في مطلع السورة إشارة إلى تمام قدرته سبحانه وتعالى ، وأنه إذا أراد شيئا يسر أسبابه؛ لأن التدبير كله له، يخفض من يشاء وإن عز، ويرفع من يشاء وإن ذل؛ ليثمرَ اعتقاد ذلك حبه، والانقطاع لعبادته، والاعتماد عليه في كل نفع ودفع؛ فإن كان هو النافع الرازق؛ فلا يستحق أحد في الوجود أن يُلجأ إليه سواه سبحانه.", "page": 103, "id": "unit-10__lesson-01__b16", "inline": [{"t": "text", "s": "1- في مطلع السورة إشارة إلى تمام قدرته "}, {"t": "honorific", "s": "سبحانه وتعالى"}, {"t": "text", "s": " ، وأنه إذا أراد شيئا يسر أسبابه؛ لأن التدبير كله له، يخفض من يشاء وإن عز، ويرفع من يشاء وإن ذل؛ ليثمرَ اعتقاد ذلك حبه، والانقطاع لعبادته، والاعتماد عليه في كل نفع ودفع؛ فإن كان هو النافع الرازق؛ فلا يستحق أحد في الوجود أن يُلجأ إليه سواه سبحانه."}], "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- رغد الرزق والأمن من المخاوف: من أكبر النعم الدنيوية الموجبة لشكر الله تعالى؛ ففي السورة دليل أن على المسلمين أفرادا وجماعات أن يقابلوا نعم الله بالشكر، وأن يشكروها بالطاعة والعبادة لله، وأن يحذروا كفران النعم: ﴿وَإِذۡ تَأَذَّنَ رَبُّكُمۡ لَئِن شَكَرۡتُمۡ لَأَزِيدَنَّكُمۡۖ وَلَئِن كَفَرۡتُمۡ إِنَّ عَذَابِي لَشَدِيدٞ ۝٧﴾.", "page": 103, "id": "unit-10__lesson-01__b17", "inline": [{"t": "text", "s": "2- رغد الرزق والأمن من المخاوف: من أكبر النعم الدنيوية الموجبة لشكر الله تعالى؛ ففي السورة دليل أن على المسلمين أفرادا وجماعات أن يقابلوا نعم الله بالشكر، وأن يشكروها بالطاعة والعبادة لله، وأن يحذروا كفران النعم: "}, {"t": "ayah", "s": "وَإِذۡ تَأَذَّنَ رَبُّكُمۡ لَئِن شَكَرۡتُمۡ لَأَزِيدَنَّكُمۡۖ وَلَئِن كَفَرۡتُمۡ إِنَّ عَذَابِي لَشَدِيدٞ ۝٧", "ayah": [7], "verses": [{"n": 7, "text": "وَإِذۡ تَأَذَّنَ رَبُّكُمۡ لَئِن شَكَرۡتُمۡ لَأَزِيدَنَّكُمۡۖ وَلَئِن كَفَرۡتُمۡ إِنَّ عَذَابِي لَشَدِيدٞ", "surah": 14, "ref_api": "https://api.quran.com/api/v4/verses/by_key/14:7", "surah_name": "ابراهيم", "ayah_canonical": 7, "match": "exact", "ref": "14:7"}], "surah": null, "ref_api": null}, {"t": "text", "s": "."}], "list": {"type": "ordered", "marker": "2"}}, {"type": "heading", "level": 3, "text": "الفوائد العلمية واللطائف:", "page": 103, "id": "unit-10__lesson-01__b18", "role": "benefits"}, {"type": "paragraph", "md": "في قوله تعالى: ﴿فَلۡيَعۡبُدُواْ رَبَّ هَٰذَا ٱلۡبَيۡتِ ۝٣﴾ دليل على أنَّ من استجاب لهذا الأمر جمع الله له بين أمن الدنيا وأمن الآخرة، ومن عصاه سلبهما منه، كما قال تعالى: ﴿وَضَرَبَ ٱللَّهُ مَثَلٗا قَرۡيَةٗ كَانَتۡ ءَامِنَةٗ مُّطۡمَئِنَّةٗ يَأۡتِيهَا رِزۡقُهَا رَغَدٗا مِّن كُلِّ مَكَانٖ فَكَفَرَتۡ بِأَنۡعُمِ ٱللَّهِ فَأَذَٰقَهَا ٱللَّهُ لِبَاسَ ٱلۡجُوعِ وَٱلۡخَوۡفِ بِمَا كَانُواْ يَصۡنَعُونَ ۝١١٢ وَلَقَدۡ جَآءَهُمۡ رَسُولٞ مِّنۡهُمۡ فَكَذَّبُوهُ فَأَخَذَهُمُ ٱلۡعَذَابُ وَهُمۡ ظَٰلِمُونَ ۝١١٣﴾.", "page": 103, "id": "unit-10__lesson-01__b19", "inline": [{"t": "text", "s": "في قوله تعالى: "}, {"t": "ayah", "s": "فَلۡيَعۡبُدُواْ رَبَّ هَٰذَا ٱلۡبَيۡتِ ۝٣", "ayah": [3], "verses": [{"n": 3, "text": "فَلۡيَعۡبُدُواْ رَبَّ هَٰذَا ٱلۡبَيۡتِ", "surah": 106, "ref_api": "https://api.quran.com/api/v4/verses/by_key/106:3", "surah_name": "قريش", "ayah_canonical": 3, "match": "exact", "ref": "106:3"}], "surah": null, "ref_api": null}, {"t": "text", "s": " دليل على أنَّ من استجاب لهذا الأمر جمع الله له بين أمن الدنيا وأمن الآخرة، ومن عصاه سلبهما منه، كما قال تعالى: "}, {"t": "ayah", "s": "وَضَرَبَ ٱللَّهُ مَثَلٗا قَرۡيَةٗ كَانَتۡ ءَامِنَةٗ مُّطۡمَئِنَّةٗ يَأۡتِيهَا رِزۡقُهَا رَغَدٗا مِّن كُلِّ مَكَانٖ فَكَفَرَتۡ بِأَنۡعُمِ ٱللَّهِ فَأَذَٰقَهَا ٱللَّهُ لِبَاسَ ٱلۡجُوعِ وَٱلۡخَوۡفِ بِمَا كَانُواْ يَصۡنَعُونَ ۝١١٢ وَلَقَدۡ جَآءَهُمۡ رَسُولٞ مِّنۡهُمۡ فَكَذَّبُوهُ فَأَخَذَهُمُ ٱلۡعَذَابُ وَهُمۡ ظَٰلِمُونَ ۝١١٣", "ayah": [112, 113], "verses": [{"n": 112, "text": "وَضَرَبَ ٱللَّهُ مَثَلٗا قَرۡيَةٗ كَانَتۡ ءَامِنَةٗ مُّطۡمَئِنَّةٗ يَأۡتِيهَا رِزۡقُهَا رَغَدٗا مِّن كُلِّ مَكَانٖ فَكَفَرَتۡ بِأَنۡعُمِ ٱللَّهِ فَأَذَٰقَهَا ٱللَّهُ لِبَاسَ ٱلۡجُوعِ وَٱلۡخَوۡفِ بِمَا كَانُواْ يَصۡنَعُونَ", "surah": 16, "ref_api": "https://api.quran.com/api/v4/verses/by_key/16:112", "surah_name": "النحل", "ayah_canonical": 112, "match": "exact", "ref": "16:112"}, {"n": 113, "text": "وَلَقَدۡ جَآءَهُمۡ رَسُولٞ مِّنۡهُمۡ فَكَذَّبُوهُ فَأَخَذَهُمُ ٱلۡعَذَابُ وَهُمۡ ظَٰلِمُونَ", "surah": 16, "ref_api": "https://api.quran.com/api/v4/verses/by_key/16:113", "surah_name": "النحل", "ayah_canonical": 113, "match": "exact", "ref": "16:113"}], "surah": null, "ref_api": null}, {"t": "text", "s": "."}]}, {"type": "heading", "level": 3, "text": "التقويم والأسئلة:", "page": 103, "id": "unit-10__lesson-01__b20", "role": "assessment"}, {"type": "paragraph", "md": "1- ما موضوع سورة قريش.", "page": 103, "id": "unit-10__lesson-01__b21", "item_role": "question", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- ما معنى الكلمات التالية: «لإيلاف».", "page": 103, "id": "unit-10__lesson-01__b22", "inline": [{"t": "text", "s": "2- ما معنى الكلمات التالية: "}, {"t": "quote", "s": "لإيلاف"}, {"t": "text", "s": "."}], "item_role": "question", "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "3-ما مقاصد سورة قريش.", "page": 103, "id": "unit-10__lesson-01__b23", "item_role": "question"}, {"type": "paragraph", "md": "4- اذكر فائدة تربوية وأخرى علمية تعلمتَها من سورة قريش.", "page": 103, "id": "unit-10__lesson-01__b24", "item_role": "question", "list": {"type": "ordered", "marker": "4"}}, {"type": "paragraph", "md": "5- اذكر المعنى الإجمالي لسورة قريش.", "page": 103, "id": "unit-10__lesson-01__b25", "item_role": "question", "list": {"type": "ordered", "marker": "5"}}, {"type": "heading", "level": 3, "text": "نشاط قراءة وسماع", "page": 103, "id": "unit-10__lesson-01__b26", "role": "activity"}, {"type": "paragraph", "md": "1- اقرأ تفسير سورة قريش من المختصر في التفسير أو تفسير السعدي واكتب أهم الفوائد التي أعجبتك، وشاركها مع معلمك أو أهل بيتك.", "page": 103, "id": "unit-10__lesson-01__b27", "item_role": "activity_step", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- استمع لتفسير سورة قريش من خلال اليوتيوب للشيخ محمد الخضيري، واكتب أهم الفوائد التي أعجبتك، وشاركها مع أصدقائك وأهل بيتك.", "page": 103, "id": "unit-10__lesson-01__b28", "item_role": "activity_step", "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "3- ابحث عن قبيلة قريش وفضلها ولماذا اختص الله هذه القبيلة ببعثة النبي صلى الله عليه وسلم منها.", "page": 103, "id": "unit-10__lesson-01__b29", "inline": [{"t": "text", "s": "3- ابحث عن قبيلة قريش وفضلها ولماذا اختص الله هذه القبيلة ببعثة النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " منها."}], "item_role": "activity_step", "list": {"type": "ordered", "marker": "3"}}]' WHERE id='unit-10__lesson-01';
INSERT INTO manhaj_lessons (id,unit_id,ord,title,subject,duration_min,hadith_count,quran_count,blocks) VALUES ('unit-10__lesson-02','unit-10',2,'تقليد الكفار واتباعهم في اللباس وغيره','الحديث',NULL,0,0,'');
UPDATE manhaj_lessons SET blocks = blocks || '[{"type": "paragraph", "md": "عَنْ ابن عمر رضي الله عنه قال: قال رَسُولَ اللَّهِ صلى الله عليه وسلم : (مَنْ ‌تَشَبَّهَ ‌بِقَوْمٍ ‌فَهُوَ ‌مِنْهُمْ) [أبو داود، وصححه الألباني].", "page": 104, "id": "unit-10__lesson-02__b01", "inline": [{"t": "text", "s": "عَنْ ابن عمر "}, {"t": "honorific", "s": "رضي الله عنه"}, {"t": "text", "s": " قال: قال رَسُولَ اللَّهِ "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : (مَنْ ‌تَشَبَّهَ ‌بِقَوْمٍ ‌فَهُوَ ‌مِنْهُمْ) [أبو داود، وصححه الألباني]."}]}, {"type": "heading", "level": 3, "text": "أهداف الدرس:", "page": 104, "id": "unit-10__lesson-02__b02", "role": "objectives"}, {"type": "paragraph", "md": "التعرف على ما تختص به هذه الأمة في لباسها وهيئتها وتميزها عن أعدائها الكفرة.", "page": 104, "id": "unit-10__lesson-02__b03"}, {"type": "paragraph", "md": "بيان الفرق بين التشبه المحرم والتشبه المباح.", "page": 104, "id": "unit-10__lesson-02__b04"}, {"type": "heading", "level": 3, "text": "شرح الحديث وبيان معانيه ومسائله:", "page": 104, "id": "unit-10__lesson-02__b05", "role": "hadith_explanation"}, {"type": "paragraph", "md": "التشبيه: هو التمثيل، والمتشابهات: هي المتماثلات، يقال: أشبه فلان فلانًا، أي: ماثله وحاكه وقلده. جاء في الصحيح أنَّ النبي صلى الله عليه وسلم قال: (لَتَتِّبعُن سَنَن من كان قبلكم حذو القُذَّة بالقُذَّة؛ حتى لو دخلوا جحر ضب لدخلتموه. قالوا: يا رسول الله؛ اليهود والنصارى؟ قال: فَمَن؟) والقذة بالقذة أي: مثلًا بمثل، فهو مثل للشيئين يستويان، ولا يتفاوتان، ‌والقُذَّة واحدة القُذَذ وهي ريش السهم؛ فله قُذَّتان متساويتان.", "page": 104, "id": "unit-10__lesson-02__b06", "inline": [{"t": "text", "s": "التشبيه: هو التمثيل، والمتشابهات: هي المتماثلات، يقال: أشبه فلان فلانًا، أي: ماثله وحاكه وقلده. جاء في الصحيح أنَّ النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " قال: "}, {"t": "emphasis", "s": "(لَتَتِّبعُن سَنَن من كان قبلكم حذو القُذَّة بالقُذَّة؛ حتى لو دخلوا جحر ضب لدخلتموه. قالوا: يا رسول الله؛ اليهود والنصارى؟ قال: فَمَن؟)", "role": "lemma"}, {"t": "text", "s": " والقذة بالقذة أي: مثلًا بمثل، فهو مثل للشيئين يستويان، ولا يتفاوتان، ‌والقُذَّة واحدة القُذَذ وهي ريش السهم؛ فله قُذَّتان متساويتان."}]}, {"type": "paragraph", "md": "من أنواع التشبه بالكافرين ما هو شرك وكفر؛ كالتشبه بالكفار في العقائد، والأمور المخلة بالتوحيد؛ كتقديس الأنبياء والصالحين وعبادتهم ودعاؤهم من دون الله، وكتحكيم الشرائع والقوانين الوضعية، ومن التشبه ما هو معصية وفسق؛ كتقليد الكفار في بعض العادات في اللباس والشَّعر ونحوه، ومنه ما هو مكروه مما لا يُعلم أهو من خصائص الفكار -فيحرم- أم لا -فيُباح-؛ فيكون مكروهًا لاشتباهه.", "page": 104, "id": "unit-10__lesson-02__b07"}, {"type": "paragraph", "md": "ما كان من قبيل العلوم والأمور المادية البحتة كالصناعات والأسلحة وغيرها؛ فالتشبه بهم هنا مباح، بل إن التفوق عليهم فيه من فروض الكفاية وإعداد العدة الواجب على المسلمين تحصيلها.", "page": 104, "id": "unit-10__lesson-02__b08"}, {"type": "heading", "level": 3, "text": "الأمور التي ورد فيها النهي عن التشبه بالكافرين أربعة أنواع:", "page": 104, "id": "unit-10__lesson-02__b09", "role": "section"}, {"type": "paragraph", "md": "1- العقائد: وهي أخطر أمور التشبه، والتشبه فيها قد يصل للكفر، كتقديس الصالحين، وصرف أي نوع من أنواع العبادة لغير الله تعالى، ومنه: التفرق في الدين، والحكم بغير ما أنزل الله والتشريع معه.", "page": 104, "id": "unit-10__lesson-02__b10", "inline": [{"t": "text", "s": "1- "}, {"t": "emphasis", "s": "العقائد", "role": "emphasis"}, {"t": "text", "s": ": وهي أخطر أمور التشبه، والتشبه فيها قد يصل للكفر، كتقديس الصالحين، وصرف أي نوع من أنواع العبادة لغير الله تعالى، ومنه: التفرق في الدين، والحكم بغير ما أنزل الله والتشريع معه."}], "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- الأعياد: وهي مشتركة بين العادات والعبادات؛ لكن خُصت بالنهي عن التشبه بالكفار فيها، وحرمة الزيادة على عيدين في السنة للمسلمين؛ فأعياد الميلاد، والأعياد الوطنية، وعيد الحب والأم والعمال.. وغيرها من الاحتفالات المنتظمة دوريا؛ كل هذا من التشبه الصريح المنهي عنه.", "page": 104, "id": "unit-10__lesson-02__b11", "inline": [{"t": "emphasis", "s": "2- الأعياد", "role": "emphasis"}, {"t": "text", "s": ": وهي مشتركة بين العادات والعبادات؛ لكن خُصت بالنهي عن التشبه بالكفار فيها، وحرمة الزيادة على عيدين في السنة للمسلمين؛ فأعياد الميلاد، والأعياد الوطنية، وعيد الحب والأم والعمال.. وغيرها من الاحتفالات المنتظمة دوريا؛ كل هذا من التشبه الصريح المنهي عنه."}], "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "3- العبادات: ومن ذلك تأخير صلاة المغرب، وترك السحور وتأخير الفطور ونحو ذلك.", "page": 104, "id": "unit-10__lesson-02__b12", "inline": [{"t": "emphasis", "s": "3- العبادات", "role": "emphasis"}, {"t": "text", "s": ": ومن ذلك تأخير صلاة المغرب، وترك السحور وتأخير الفطور ونحو ذلك."}], "list": {"type": "ordered", "marker": "3"}}, {"type": "paragraph", "md": "4- العادات والأخلاق والسلوك واللباس «الهدي الظاهر»: فقد ورد النهي عن أمور عدة في الشرع لعلة التشبه؛ كالنهي عن حلق اللحى، والقزع، واتخاذ آنية الذهب، ولبس ما هو من شعار الكفار، وعن التبرج والاختلاط وتشبه الرجال بالنساء، والنساء بالرجال وغيرها من العادات.", "page": 105, "id": "unit-10__lesson-02__b13", "inline": [{"t": "text", "s": "4- العادات والأخلاق والسلوك واللباس "}, {"t": "quote", "s": "الهدي الظاهر"}, {"t": "text", "s": ": فقد ورد النهي عن أمور عدة في الشرع لعلة التشبه؛ كالنهي عن حلق اللحى، والقزع، واتخاذ آنية الذهب، ولبس ما هو من شعار الكفار، وعن التبرج والاختلاط وتشبه الرجال بالنساء، والنساء بالرجال وغيرها من العادات."}], "list": {"type": "ordered", "marker": "4"}}, {"type": "heading", "level": 3, "text": "لما ذا نُهينا عن التشبه بالكافرين؟", "page": 105, "id": "unit-10__lesson-02__b14", "role": "section"}, {"type": "paragraph", "md": "تسليمًا لأمر الله تعالى، فإنَّ هذا من صميم الإيمان، والتسليم: التصديق فيما أخبر وامتثال أمره.", "page": 105, "id": "unit-10__lesson-02__b15"}, {"type": "paragraph", "md": "أعمال الكفار مبناها على الضلال والفساد؛ سوء ظهر الفساد أو خفي؛ فمتابعتهم دخول في الفساد.", "page": 105, "id": "unit-10__lesson-02__b16"}, {"type": "paragraph", "md": "التشبه في الغالب يوقع شيئًا من المشاكلة بين المتشبه والمتشبه به وبين المقلِد والمقَلد، والمشاكلة بمعنى التناسب والميول والانصهار والموافقة في الأعمال والأقوال، وهذا أمر لا ينبغي لمسلم أن يقع فيه.", "page": 105, "id": "unit-10__lesson-02__b17"}, {"type": "paragraph", "md": "التشبه بالكافرين يورث غالبًا ازدراء السنة والحق الذي جاء به الرسول صلى الله عليه وسلم وأصحابه؛ لأن من تشبه بقوم وافقهم وأعجبه ذلك منهم، وهذا ما يجعل المسلم يشعر بالذل والضعف والانهزامية نحو الكفار.", "page": 105, "id": "unit-10__lesson-02__b18", "inline": [{"t": "text", "s": "التشبه بالكافرين يورث غالبًا ازدراء السنة والحق الذي جاء به الرسول "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " وأصحابه؛ لأن من تشبه بقوم وافقهم وأعجبه ذلك منهم، وهذا ما يجعل المسلم يشعر بالذل والضعف والانهزامية نحو الكفار."}]}, {"type": "paragraph", "md": "المشابهة تورث المودة والمحبة والمولاة؛ فإن المسلم إذا قلد الكافر وجد في نفسه إلفة له، وهذه الإلفة تورث المحبة والموالاة وشيئًا من التوافق بين المتشابِهَين، وهذا أمر فطري يدركه العقلاء، خاصة إذا كان المقلد ضعيفًا منهزما نفسيًّا؛ فتقليد الكافر يُشعره بعظمة المقلَّد ومودته، ولو لم يكن سوى التناسب الظاهر لكفى؛ فكيف وهو يورث تناسبًا ومحبة باطنة؟ فلو أن إنسانًا ذهب لبد يكون فيه غريبًا، ثمَّ رأى من يلبس كلباسه ويتكلم بلغته فإنه لا بد وأن يشعر نحوه بشيء من المودة أكثر مما لو كان في بلده؛ فهذا التقليد لا بد أن يقع أثره في القلب، ومثله لو قلد المسلمُ الكافرَ عن إعجاب؛ فمآله أن يورث المحبة المحرمة.", "page": 105, "id": "unit-10__lesson-02__b19"}, {"type": "heading", "level": 3, "text": "التقويم والأسئلة:", "page": 105, "id": "unit-10__lesson-02__b20", "role": "assessment"}, {"type": "paragraph", "md": "ما ضابط التشبه المنهي عنه؟ ولماذا نهت الشريعة عن التشبه بالكفار؟", "page": 105, "id": "unit-10__lesson-02__b21", "item_role": "question"}, {"type": "paragraph", "md": "اذكر أربعة أمثلة على التشبه بالكافرين في الهدي الظاهر من اللباس والعادات.", "page": 105, "id": "unit-10__lesson-02__b22", "item_role": "question"}, {"type": "heading", "level": 3, "text": "نشاط من كتاب", "page": 105, "id": "unit-10__lesson-02__b23", "role": "activity"}, {"type": "paragraph", "md": "1- توجد عشرات الأمور نهى عنها النبي صلى الله عليه وسلم لعلة التشبه بالكافرين؛ اذكر خمسة منها.", "page": 105, "id": "unit-10__lesson-02__b24", "inline": [{"t": "text", "s": "1- توجد عشرات الأمور نهى عنها النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " لعلة التشبه بالكافرين؛ اذكر خمسة منها."}], "item_role": "activity_step", "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "2- ارجع إلى كتاب «سلطة الثقافة الغالبة» للشيخ إبراهيم السكران، وانقل لنا فوائدك منه.", "page": 105, "id": "unit-10__lesson-02__b25", "inline": [{"t": "text", "s": "2- ارجع إلى كتاب "}, {"t": "quote", "s": "سلطة الثقافة الغالبة"}, {"t": "text", "s": " للشيخ إبراهيم السكران، وانقل لنا فوائدك منه."}], "item_role": "activity_step", "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "3- تنتشر في مجتمعنا وأسرنا بعض ظواهر التشبه بالكفار؛ تعرف على واحدة منها وأنكرها..", "page": 105, "id": "unit-10__lesson-02__b26", "item_role": "activity_step", "list": {"type": "ordered", "marker": "3"}}]' WHERE id='unit-10__lesson-02';
INSERT INTO manhaj_lessons (id,unit_id,ord,title,subject,duration_min,hadith_count,quran_count,blocks) VALUES ('unit-10__lesson-03','unit-10',3,'أركان الإيمان الستة؛ الإيمان بالله','التوحيد والعقيدة',NULL,0,28,'');
UPDATE manhaj_lessons SET blocks = blocks || '[{"type": "heading", "level": 3, "text": "أهداف الدرس:", "page": 106, "id": "unit-10__lesson-03__b01", "role": "objectives"}, {"type": "paragraph", "md": "التعرف على أركان الإيمان الستة؛ التي لا يصح إيمان المسلم إلا بها.", "page": 106, "id": "unit-10__lesson-03__b02"}, {"type": "paragraph", "md": "بيان معنى الإيمان بالله وأقسام التوحيد الثلاثة وحقيقتها وأدلتها.", "page": 106, "id": "unit-10__lesson-03__b03"}, {"type": "paragraph", "md": "أركان الإيمان الستة: الإيمان بالله، وملائكته، وكتبه، ورسله، واليوم الآخر، والقدر خيره وشره.", "page": 106, "id": "unit-10__lesson-03__b04"}, {"type": "paragraph", "md": "وأولها: الإيمان بالله، وهو أساس للإيمان بكلِّ ما يجب الإيمان به من الأركان الأخرى، ولهذا أُضيف إليه الملائكة والكتب والرسل، فمَن لَم يؤمن بالله ربًّا وإلهًا فإنه لن يؤمن ببقيَّة الأركان، والإيمان بالله يشمل الإيمان بوجوده وربوبيَّته وألوهيَّته وأسمائه وصفاته، وأنَّه سبحانه وتعالى متَّصفٌ بكلِّ كمال يليق به، منَزَّهٌ عن كلِّ نقص، فيجب توحيده بربوبيَّته وألوهيَّته وأسمائه وصفاته.. وهذه أقسام التوحيد الثلاثة.", "page": 106, "id": "unit-10__lesson-03__b05", "inline": [{"t": "text", "s": "وأولها: الإيمان بالله، وهو أساس للإيمان بكلِّ ما يجب الإيمان به من الأركان الأخرى، ولهذا أُضيف إليه الملائكة والكتب والرسل، فمَن لَم يؤمن بالله ربًّا وإلهًا فإنه لن يؤمن ببقيَّة الأركان، والإيمان بالله يشمل الإيمان بوجوده وربوبيَّته وألوهيَّته وأسمائه وصفاته، وأنَّه "}, {"t": "honorific", "s": "سبحانه وتعالى"}, {"t": "text", "s": " متَّصفٌ بكلِّ كمال يليق به، منَزَّهٌ عن كلِّ نقص، فيجب توحيده بربوبيَّته وألوهيَّته وأسمائه وصفاته.. وهذه أقسام التوحيد الثلاثة."}]}, {"type": "paragraph", "md": "1- توحيد الربوبية: هو الاعتقادُ بأن ربَّ العالَم وخالقه واحدٌ، الذي جُبلت الفِطَرُ السليمةُ على الإِقرار به، والخضوع له؛ فوجوده سبحانه وتعالى أحقُّ الحق، والشك في وجوده كفر وظلم، قال تعالى: ﴿قَالَتۡ رُسُلُهُمۡ أَفِي ٱللَّهِ شَكّٞ﴾، ولما سمع جبير بن مطعم رضي الله عنه رسول الله صلى الله عليه وسلم يقرأ سورة الطور فبلغ قوله تعالى: ﴿أَمۡ خُلِقُواْ مِنۡ غَيۡرِ شَيۡءٍ أَمۡ هُمُ ٱلۡخَٰلِقُونَ ۝٣٥ أَمۡ خَلَقُواْ ٱلسَّمَٰوَٰتِ وَٱلۡأَرۡضَۚ بَل لَّا يُوقِنُونَ ۝٣٦ أَمۡ عِندَهُمۡ خَزَآئِنُ رَبِّكَ أَمۡ هُمُ ٱلۡمُصَۜيۡطِرُونَ ۝٣٧﴾ وكان يومئذ مشركا قال: «كاد قلبي أن يطير، وذلك أول ما وقر الإيمان في قلبي».", "page": 106, "id": "unit-10__lesson-03__b06", "inline": [{"t": "text", "s": "1- توحيد الربوبية: هو الاعتقادُ بأن ربَّ العالَم وخالقه واحدٌ، الذي جُبلت الفِطَرُ السليمةُ على الإِقرار به، والخضوع له؛ فوجوده "}, {"t": "honorific", "s": "سبحانه وتعالى"}, {"t": "text", "s": " أحقُّ الحق، والشك في وجوده كفر وظلم، قال تعالى: "}, {"t": "ayah", "s": "قَالَتۡ رُسُلُهُمۡ أَفِي ٱللَّهِ شَكّٞ", "ayah": [], "verses": [{"n": 10, "text": "قَالَتۡ رُسُلُهُمۡ أَفِي ٱللَّهِ شَكّٞ", "surah": 14, "surah_name": "ابراهيم", "ref": "14:10", "ref_api": "https://api.quran.com/api/v4/verses/by_key/14:10"}], "surah": 14, "ref_api": "https://api.quran.com/api/v4/verses/by_key/14:10", "surah_name": "ابراهيم", "ayah_canonical": 10, "match": "contained", "ref": "14:10"}, {"t": "text", "s": "، ولما سمع جبير بن مطعم "}, {"t": "honorific", "s": "رضي الله عنه"}, {"t": "text", "s": " رسول الله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " يقرأ سورة الطور فبلغ قوله تعالى: "}, {"t": "ayah", "s": "أَمۡ خُلِقُواْ مِنۡ غَيۡرِ شَيۡءٍ أَمۡ هُمُ ٱلۡخَٰلِقُونَ ۝٣٥ أَمۡ خَلَقُواْ ٱلسَّمَٰوَٰتِ وَٱلۡأَرۡضَۚ بَل لَّا يُوقِنُونَ ۝٣٦ أَمۡ عِندَهُمۡ خَزَآئِنُ رَبِّكَ أَمۡ هُمُ ٱلۡمُصَۜيۡطِرُونَ ۝٣٧", "ayah": [35, 36, 37], "verses": [{"n": 35, "text": "أَمۡ خُلِقُواْ مِنۡ غَيۡرِ شَيۡءٍ أَمۡ هُمُ ٱلۡخَٰلِقُونَ", "surah": 52, "ref_api": "https://api.quran.com/api/v4/verses/by_key/52:35", "surah_name": "الطور", "ayah_canonical": 35, "match": "exact", "ref": "52:35"}, {"n": 36, "text": "أَمۡ خَلَقُواْ ٱلسَّمَٰوَٰتِ وَٱلۡأَرۡضَۚ بَل لَّا يُوقِنُونَ", "surah": 52, "ref_api": "https://api.quran.com/api/v4/verses/by_key/52:36", "surah_name": "الطور", "ayah_canonical": 36, "match": "exact", "ref": "52:36"}, {"n": 37, "text": "أَمۡ عِندَهُمۡ خَزَآئِنُ رَبِّكَ أَمۡ هُمُ ٱلۡمُصَۜيۡطِرُونَ", "surah": 52, "ref_api": "https://api.quran.com/api/v4/verses/by_key/52:37", "surah_name": "الطور", "ayah_canonical": 37, "match": "exact", "ref": "52:37"}], "surah": null, "ref_api": null}, {"t": "text", "s": " وكان يومئذ مشركا قال: "}, {"t": "quote", "s": "كاد قلبي أن يطير، وذلك أول ما وقر الإيمان في قلبي"}, {"t": "text", "s": "."}], "list": {"type": "ordered", "marker": "1"}}, {"type": "paragraph", "md": "إن كل مخلوق قد فُطر على الإيمان بخالقه من غير سبق تعليم، وها نحن نرى إجابة السائلين ما يدل دلالة يقينية على وجوده تعالى، وهو القائل: ﴿إِذۡ تَسۡتَغِيثُونَ رَبَّكُمۡ فَٱسۡتَجَابَ لَكُمۡ﴾، ومن المعلوم عند كل شخص أن الحادث لا بد له من محدِث، وهذه المخلوقات الكثيرة والتي نشاهدها في كل وقت لا بد لها من خالق أَوْجدها، وهو الله عز وجل ؛ لأنه يمتنع أن تكون مخلوقة من غير خالق خلقها، كما يمتنع أن تخلق نفسها؛ لأن الشيء لا يخلق نفسه؛ كما قال تعالى: ﴿أَمۡ خُلِقُواْ مِنۡ غَيۡرِ شَيۡءٍ أَمۡ هُمُ ٱلۡخَٰلِقُونَ ۝٣٥﴾، ومعنى الآية: أنهم لم يُخلقوا من غير خالق، ولا هم الذين خلقوا أنفسهم، فيتعين أن يكون خالقهم هو الله تبارك وتعالى .", "page": 106, "id": "unit-10__lesson-03__b07", "inline": [{"t": "text", "s": "إن كل مخلوق قد فُطر على الإيمان بخالقه من غير سبق تعليم، وها نحن نرى إجابة السائلين ما يدل دلالة يقينية على وجوده تعالى، وهو القائل: "}, {"t": "ayah", "s": "إِذۡ تَسۡتَغِيثُونَ رَبَّكُمۡ فَٱسۡتَجَابَ لَكُمۡ", "ayah": [], "verses": [{"n": 9, "text": "إِذۡ تَسۡتَغِيثُونَ رَبَّكُمۡ فَٱسۡتَجَابَ لَكُمۡ", "surah": 8, "surah_name": "الأنفال", "ref": "8:9", "ref_api": "https://api.quran.com/api/v4/verses/by_key/8:9"}], "surah": 8, "ref_api": "https://api.quran.com/api/v4/verses/by_key/8:9", "surah_name": "الأنفال", "ayah_canonical": 9, "match": "contained", "ref": "8:9"}, {"t": "text", "s": "، ومن المعلوم عند كل شخص أن الحادث لا بد له من محدِث، وهذه المخلوقات الكثيرة والتي نشاهدها في كل وقت لا بد لها من خالق أَوْجدها، وهو الله "}, {"t": "honorific", "s": "عز وجل"}, {"t": "text", "s": " ؛ لأنه يمتنع أن تكون مخلوقة من غير خالق خلقها، كما يمتنع أن تخلق نفسها؛ لأن الشيء لا يخلق نفسه؛ كما قال تعالى: "}, {"t": "ayah", "s": "أَمۡ خُلِقُواْ مِنۡ غَيۡرِ شَيۡءٍ أَمۡ هُمُ ٱلۡخَٰلِقُونَ ۝٣٥", "ayah": [35], "verses": [{"n": 35, "text": "أَمۡ خُلِقُواْ مِنۡ غَيۡرِ شَيۡءٍ أَمۡ هُمُ ٱلۡخَٰلِقُونَ", "surah": 52, "ref_api": "https://api.quran.com/api/v4/verses/by_key/52:35", "surah_name": "الطور", "ayah_canonical": 35, "match": "exact", "ref": "52:35"}], "surah": null, "ref_api": null}, {"t": "text", "s": "، ومعنى الآية: أنهم لم يُخلقوا من غير خالق، ولا هم الذين خلقوا أنفسهم، فيتعين أن يكون خالقهم هو الله "}, {"t": "honorific", "s": "تبارك وتعالى"}, {"t": "text", "s": " ."}]}, {"type": "paragraph", "md": "إن انتظام هذا الكون بسمائه وأرضه ونجومه وأشجاره يدل دلالة قطعية على أن لهذا الكون خالقًا موحدًا وهو الله سبحانه وتعالى : ﴿صُنۡعَ ٱللَّهِ ٱلَّذِيٓ أَتۡقَنَ كُلَّ شَيۡءٍۚ﴾؛ فهذه الكواكب والنجوم -مثلًا- تسير على نظام ثابت لا يختل، وكل كوكب يسير في مجال لا يتعداه ولا يتجاوزه؛ يقول تعالى: ﴿لَا ٱلشَّمۡسُ يَنۢبَغِي لَهَآ أَن تُدۡرِكَ ٱلۡقَمَرَ وَلَا ٱلَّيۡلُ سَابِقُ ٱلنَّهَارِۚ وَكُلّٞ فِي فَلَكٖ يَسۡبَحُونَ ۝٤٠﴾.", "page": 106, "id": "unit-10__lesson-03__b08", "inline": [{"t": "text", "s": "إن انتظام هذا الكون بسمائه وأرضه ونجومه وأشجاره يدل دلالة قطعية على أن لهذا الكون خالقًا موحدًا وهو الله "}, {"t": "honorific", "s": "سبحانه وتعالى"}, {"t": "text", "s": " : "}, {"t": "ayah", "s": "صُنۡعَ ٱللَّهِ ٱلَّذِيٓ أَتۡقَنَ كُلَّ شَيۡءٍۚ", "ayah": [], "verses": [{"n": 88, "text": "صُنۡعَ ٱللَّهِ ٱلَّذِيٓ أَتۡقَنَ كُلَّ شَيۡءٍۚ", "surah": 27, "surah_name": "النمل", "ref": "27:88", "ref_api": "https://api.quran.com/api/v4/verses/by_key/27:88"}], "surah": 27, "ref_api": "https://api.quran.com/api/v4/verses/by_key/27:88", "surah_name": "النمل", "ayah_canonical": 88, "match": "contained", "ref": "27:88"}, {"t": "text", "s": "؛ فهذه الكواكب والنجوم -مثلًا- تسير على نظام ثابت لا يختل، وكل كوكب يسير في مجال لا يتعداه ولا يتجاوزه؛ يقول تعالى: "}, {"t": "ayah", "s": "لَا ٱلشَّمۡسُ يَنۢبَغِي لَهَآ أَن تُدۡرِكَ ٱلۡقَمَرَ وَلَا ٱلَّيۡلُ سَابِقُ ٱلنَّهَارِۚ وَكُلّٞ فِي فَلَكٖ يَسۡبَحُونَ ۝٤٠", "ayah": [40], "verses": [{"n": 40, "text": "لَا ٱلشَّمۡسُ يَنۢبَغِي لَهَآ أَن تُدۡرِكَ ٱلۡقَمَرَ وَلَا ٱلَّيۡلُ سَابِقُ ٱلنَّهَارِۚ وَكُلّٞ فِي فَلَكٖ يَسۡبَحُونَ", "surah": 36, "ref_api": "https://api.quran.com/api/v4/verses/by_key/36:40", "surah_name": "يس", "ayah_canonical": 40, "match": "exact", "ref": "36:40"}], "surah": null, "ref_api": null}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "ومعنى توحيد الربوبية: الإقرارُ بأنَّ الله واحد في أفعاله، لا شريك له فيها؛ كالخَلق والرَّزق والإحياء والإماتة، وتدبير الأمور والتصرُّف في الكون، وغير ذلك مِمَّا يتعلَّق بربوبيَّته سبحانه وتعالى .", "page": 107, "id": "unit-10__lesson-03__b09", "inline": [{"t": "emphasis", "s": "ومعنى توحيد الربوبية", "role": "emphasis"}, {"t": "text", "s": ": الإقرارُ بأنَّ الله واحد في أفعاله، لا شريك له فيها؛ كالخَلق والرَّزق والإحياء والإماتة، وتدبير الأمور والتصرُّف في الكون، وغير ذلك مِمَّا يتعلَّق بربوبيَّته "}, {"t": "honorific", "s": "سبحانه وتعالى"}, {"t": "text", "s": " ."}]}, {"type": "paragraph", "md": "ولا شك أن تحقيق توحيد الربوبية ومعرفة الله بأسمائه وصفاته يجعلنا نقر مباشرة بتوحيد الألوهية؛ كما قال تعالى في كتابه الكريم ﴿أَلَا لَهُ ٱلۡخَلۡقُ وَٱلۡأَمۡرُۗ﴾؛ فطالما أنه وحده مَن خلق فهو وحده من يأمر، قال تعالى: ﴿أَمَّن يَبۡدَؤُاْ ٱلۡخَلۡقَ ثُمَّ يُعِيدُهُۥ وَمَن يَرۡزُقُكُم مِّنَ ٱلسَّمَآءِ وَٱلۡأَرۡضِۗ أَءِلَٰهٞ مَّعَ ٱللَّهِۚ قُلۡ هَاتُواْ بُرۡهَٰنَكُمۡ إِن كُنتُمۡ صَٰدِقِينَ۝٦٤﴾؛ فطالما هو وحده من يرزق فلا بُد ألا يُؤله -أي يعبد- غيره، وهكذا في كل أوصاف ربوبيته..", "page": 107, "id": "unit-10__lesson-03__b10", "inline": [{"t": "text", "s": "ولا شك أن تحقيق توحيد الربوبية ومعرفة الله بأسمائه وصفاته يجعلنا نقر مباشرة بتوحيد الألوهية؛ كما قال تعالى في كتابه الكريم "}, {"t": "ayah", "s": "أَلَا لَهُ ٱلۡخَلۡقُ وَٱلۡأَمۡرُۗ", "ayah": [], "verses": [{"n": 54, "text": "أَلَا لَهُ ٱلۡخَلۡقُ وَٱلۡأَمۡرُۗ", "surah": 7, "surah_name": "الأعراف", "ref": "7:54", "ref_api": "https://api.quran.com/api/v4/verses/by_key/7:54"}], "surah": 7, "ref_api": "https://api.quran.com/api/v4/verses/by_key/7:54", "surah_name": "الأعراف", "ayah_canonical": 54, "match": "contained", "ref": "7:54"}, {"t": "text", "s": "؛ فطالما أنه وحده مَن خلق فهو وحده من يأمر، قال تعالى: "}, {"t": "ayah", "s": "أَمَّن يَبۡدَؤُاْ ٱلۡخَلۡقَ ثُمَّ يُعِيدُهُۥ وَمَن يَرۡزُقُكُم مِّنَ ٱلسَّمَآءِ وَٱلۡأَرۡضِۗ أَءِلَٰهٞ مَّعَ ٱللَّهِۚ قُلۡ هَاتُواْ بُرۡهَٰنَكُمۡ إِن كُنتُمۡ صَٰدِقِينَ۝٦٤", "ayah": [64], "verses": [{"n": 64, "text": "أَمَّن يَبۡدَؤُاْ ٱلۡخَلۡقَ ثُمَّ يُعِيدُهُۥ وَمَن يَرۡزُقُكُم مِّنَ ٱلسَّمَآءِ وَٱلۡأَرۡضِۗ أَءِلَٰهٞ مَّعَ ٱللَّهِۚ قُلۡ هَاتُواْ بُرۡهَٰنَكُمۡ إِن كُنتُمۡ صَٰدِقِينَ", "surah": 27, "ref_api": "https://api.quran.com/api/v4/verses/by_key/27:64", "surah_name": "النمل", "ayah_canonical": 64, "match": "exact", "ref": "27:64"}], "surah": null, "ref_api": null}, {"t": "text", "s": "؛ فطالما هو وحده من يرزق فلا بُد ألا يُؤله -أي يعبد- غيره، وهكذا في كل أوصاف ربوبيته.."}]}, {"type": "paragraph", "md": "2- توحيد الألوهية: هو توحيد الله بالعبادة، أو يُقال: توحيد الله بأفعال العباد؛ كالصلاة والصيام والزكاة والدعاء والخوف والرَّجاء والتوكُّل والاستعانة والاستعاذة والاستغاثة والذَّبح والنَّذر والحكم بين العباد وموالاة مَن أمر الله بموالاته ومعاداة من أمر الله بمعاداته، وغيرها من أنواع العبادة التي يجب إفراده بها؛ فلا يُصرف منها شيء لغيره، ولو كان ملَكًا مقرَّبًا أو نبيًّا مرسَلًا، فضلًا عن غيرهما، وهو معنى «لا إله إلا الله».", "page": 107, "id": "unit-10__lesson-03__b11", "inline": [{"t": "text", "s": "2- توحيد الألوهية: هو توحيد الله بالعبادة، أو يُقال: توحيد الله بأفعال العباد؛ كالصلاة والصيام والزكاة والدعاء والخوف والرَّجاء والتوكُّل والاستعانة والاستعاذة والاستغاثة والذَّبح والنَّذر والحكم بين العباد وموالاة مَن أمر الله بموالاته ومعاداة من أمر الله بمعاداته، وغيرها من أنواع العبادة التي يجب إفراده بها؛ فلا يُصرف منها شيء لغيره، ولو كان ملَكًا مقرَّبًا أو نبيًّا مرسَلًا، فضلًا عن غيرهما، وهو معنى "}, {"t": "quote", "s": "لا إله إلا الله"}, {"t": "text", "s": "."}], "list": {"type": "ordered", "marker": "2"}}, {"type": "paragraph", "md": "3- توحيد الأسماء والصفات: هو إثبات كلِّ ما أثبته لنفسه وأثبته له رسوله من الأسماء والصفات على وجه يليق بكماله وجلاله، دون تكييف أو تمثيل، ودون تحريف أو تأويل أو تعطيل. وتنزيهه عن كلِّ ما لا يليق به، كما قال الله عز وجل : ﴿لَيۡسَ كَمِثۡلِهِۦ شَيۡءٞۖ وَهُوَ ٱلسَّمِيعُ ٱلۡبَصِيرُ ۝١١﴾؛ فجمع في هذه الآية بين الإثبات والتنزيه، فالإثبات في قوله: ﴿وَهُوَ ٱلسَّمِيعُ ٱلۡبَصِيرُ ۝١١﴾، والتنزيه في قوله: ﴿لَيۡسَ كَمِثۡلِهِۦ شَيۡءٞۖ﴾؛ فله سبحانه وتعالى سمع لا كالأسماع، وبصر لا كالأبصار، وهكذا يُقال في كلِّ ما ثبت لله من الأسماء والصفات.", "page": 107, "id": "unit-10__lesson-03__b12", "inline": [{"t": "text", "s": "3- توحيد الأسماء والصفات: هو إثبات كلِّ ما أثبته لنفسه وأثبته له رسوله من الأسماء والصفات على وجه يليق بكماله وجلاله، دون تكييف أو تمثيل، ودون تحريف أو تأويل أو تعطيل. وتنزيهه عن كلِّ ما لا يليق به، كما قال الله "}, {"t": "honorific", "s": "عز وجل"}, {"t": "text", "s": " : "}, {"t": "ayah", "s": "لَيۡسَ كَمِثۡلِهِۦ شَيۡءٞۖ وَهُوَ ٱلسَّمِيعُ ٱلۡبَصِيرُ ۝١١", "ayah": [11], "verses": [{"n": 11, "text": "لَيۡسَ كَمِثۡلِهِۦ شَيۡءٞۖ وَهُوَ ٱلسَّمِيعُ ٱلۡبَصِيرُ", "surah": 42, "ref_api": "https://api.quran.com/api/v4/verses/by_key/42:11", "surah_name": "الشورى", "ayah_canonical": 11, "match": "contained", "ref": "42:11"}], "surah": null, "ref_api": null}, {"t": "text", "s": "؛ فجمع في هذه الآية بين الإثبات والتنزيه، فالإثبات في قوله: "}, {"t": "ayah", "s": "وَهُوَ ٱلسَّمِيعُ ٱلۡبَصِيرُ ۝١١", "ayah": [11], "verses": [{"n": 11, "text": "وَهُوَ ٱلسَّمِيعُ ٱلۡبَصِيرُ", "surah": 42, "ref_api": "https://api.quran.com/api/v4/verses/by_key/42:11", "surah_name": "الشورى", "ayah_canonical": 11, "match": "contained", "ref": "42:11"}], "surah": null, "ref_api": null}, {"t": "text", "s": "، والتنزيه في قوله: "}, {"t": "ayah", "s": "لَيۡسَ كَمِثۡلِهِۦ شَيۡءٞۖ", "ayah": [], "verses": [{"n": 11, "text": "لَيۡسَ كَمِثۡلِهِۦ شَيۡءٞۖ", "surah": 42, "surah_name": "الشورى", "ref": "42:11", "ref_api": "https://api.quran.com/api/v4/verses/by_key/42:11"}], "surah": 42, "ref_api": "https://api.quran.com/api/v4/verses/by_key/42:11", "surah_name": "الشورى", "ayah_canonical": 11, "match": "contained", "ref": "42:11"}, {"t": "text", "s": "؛ فله "}, {"t": "honorific", "s": "سبحانه وتعالى"}, {"t": "text", "s": " سمع لا كالأسماع، وبصر لا كالأبصار، وهكذا يُقال في كلِّ ما ثبت لله من الأسماء والصفات."}], "list": {"type": "ordered", "marker": "3"}}, {"type": "paragraph", "md": "ومما جاء من آيات الصفات: قول الله عز وجل : ﴿وَيَبۡقَىٰ وَجۡهُ رَبِّكَ ذُو ٱلۡجَلَٰلِ وَٱلۡإِكۡرَامِ ۝٢٧﴾، وقوله سبحانه وتعالى : ﴿وَقَالَتِ ٱلۡيَهُودُ يَدُ ٱللَّهِ مَغۡلُولَةٌۚ غُلَّتۡ أَيۡدِيهِمۡ وَلُعِنُواْ بِمَا قَالُواْۘ بَلۡ يَدَاهُ مَبۡسُوطَتَانِ يُنفِقُ كَيۡفَ يَشَآءُۚ﴾، وقوله تعالى إخبارا عن عيسى عليه السلام أنه قال: ﴿تَعۡلَمُ مَا فِي نَفۡسِي وَلَآ أَعۡلَمُ مَا فِي نَفۡسِكَۚ إِنَّكَ أَنتَ عَلَّٰمُ ٱلۡغُيُوبِ﴾، وقوله سبحانه: ﴿هَلۡ يَنظُرُونَ إِلَّآ أَن يَأۡتِيَهُمُ ٱللَّهُ فِي ظُلَلٖ مِّنَ ٱلۡغَمَامِ وَٱلۡمَلَٰٓئِكَةُ وَقُضِيَ ٱلۡأَمۡرُۚ وَإِلَى ٱللَّهِ تُرۡجَعُ ٱلۡأُمُورُ﴾، وقوله تعالى: ﴿فَقَدۡ ءَاتَيۡنَآ ءَالَ إِبۡرَٰهِيمَ ٱلۡكِتَٰبَ وَٱلۡحِكۡمَةَ وَءَاتَيۡنَٰهُم مُّلۡكًا عَظِيمٗا ۝٥٤﴾، وقوله تعالى في الكفار: ﴿وَيُعَذِّبَ ٱلۡمُنَٰفِقِينَ وَٱلۡمُنَٰفِقَٰتِ وَٱلۡمُشۡرِكِينَ وَٱلۡمُشۡرِكَٰتِ ٱلظَّآنِّينَ بِٱللَّهِ ظَنَّ ٱلسَّوۡءِۚ عَلَيۡهِمۡ دَآئِرَةُ ٱلسَّوۡءِۖ وَغَضِبَ ٱللَّهُ عَلَيۡهِمۡ وَلَعَنَهُمۡ وَأَعَدَّ لَهُمۡ جَهَنَّمَۖ وَسَآءَتۡ مَصِيرٗا ۝٦﴾، وقوله تعالى: ﴿ذَٰلِكَ بِأَنَّهُمۡ قَالُواْ لِلَّذِينَ كَرِهُواْ مَا نَزَّلَ ٱللَّهُ سَنُطِيعُكُمۡ فِي بَعۡضِ ٱلۡأَمۡرِۖ وَٱللَّهُ يَعۡلَمُ إِسۡرَارَهُمۡ ۝٢٦﴾، وقوله تعالى: ﴿وَلَٰكِن كَرِهَ ٱللَّهُ ٱنۢبِعَاثَهُمۡ فَثَبَّطَهُمۡ وَقِيلَ ٱقۡعُدُواْ مَعَ ٱلۡقَٰعِدِينَ ۝٤٦﴾.", "page": 107, "id": "unit-10__lesson-03__b13", "inline": [{"t": "emphasis", "s": "ومما جاء من آيات الصفات:", "role": "emphasis"}, {"t": "text", "s": " قول الله "}, {"t": "honorific", "s": "عز وجل"}, {"t": "text", "s": " : "}, {"t": "ayah", "s": "وَيَبۡقَىٰ وَجۡهُ رَبِّكَ ذُو ٱلۡجَلَٰلِ وَٱلۡإِكۡرَامِ ۝٢٧", "ayah": [27], "verses": [{"n": 27, "text": "وَيَ