", "surah": 47, "ref_api": "https://api.quran.com/api/v4/verses/by_key/47:26", "surah_name": "محمد", "ayah_canonical": 26, "match": "exact", "ref": "47:26"}], "surah": null, "ref_api": null}, {"t": "text", "s": "، وقوله تعالى: "}, {"t": "ayah", "s": "وَلَٰكِن كَرِهَ ٱللَّهُ ٱنۢبِعَاثَهُمۡ فَثَبَّطَهُمۡ وَقِيلَ ٱقۡعُدُواْ مَعَ ٱلۡقَٰعِدِينَ ۝٤٦", "ayah": [46], "verses": [{"n": 46, "text": "وَلَٰكِن كَرِهَ ٱللَّهُ ٱنۢبِعَاثَهُمۡ فَثَبَّطَهُمۡ وَقِيلَ ٱقۡعُدُواْ مَعَ ٱلۡقَٰعِدِينَ", "surah": 9, "ref_api": "https://api.quran.com/api/v4/verses/by_key/9:46", "surah_name": "التوبة", "ayah_canonical": 46, "match": "contained", "ref": "9:46"}], "surah": null, "ref_api": null}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "ومن السنة، قول النبي صلى الله عليه وسلم : (ينزل ربنا تبارك وتعالى كل ليلة إلى سماء الدنيا)، وقوله: (يعجب ربك من الشاب ليست له صبوة)، وقوله: ( يضحك الله إلى رجلين قتل أحدهما الآخر ثم يدخلان الجنة).", "page": 108, "id": "unit-10__lesson-03__b14", "inline": [{"t": "emphasis", "s": "ومن السنة", "role": "emphasis"}, {"t": "text", "s": "، قول النبي "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : ("}, {"t": "emphasis", "s": "ينزل ربنا", "role": "emphasis"}, {"t": "text", "s": " "}, {"t": "honorific", "s": "تبارك وتعالى"}, {"t": "text", "s": " "}, {"t": "emphasis", "s": "كل ليلة إلى سماء الدنيا", "role": "emphasis"}, {"t": "text", "s": ")، وقوله: ("}, {"t": "emphasis", "s": "يعجب ربك من الشاب ليست له صبوة", "role": "emphasis"}, {"t": "text", "s": ")، وقوله: ( "}, {"t": "emphasis", "s": "يضحك الله إلى رجلين قتل أحدهما الآخر ثم يدخلان الجنة", "role": "emphasis"}, {"t": "text", "s": ")."}]}, {"type": "paragraph", "md": "فهذا وما أشبهه مما صح سنده: نؤمن به، ولا نرده ولا نجحده ولا نتأوله بتأويل يخالف ظاهره، ولا نشبهه بصفات المخلوقين، ولا نمثله ولا نكيفه، ونعتقد فيه ما ثبت في كتابه، وسنة نبيه صلى الله عليه وسلم ، ونقطع الوهم والظن عن غير ذلك؛ فالله سبحانه وتعالى : ﴿لَيۡسَ كَمِثۡلِهِۦ شَيۡءٞۖ وَهُوَ ٱلسَّمِيعُ ٱلۡبَصِيرُ ۝١١﴾.", "page": 108, "id": "unit-10__lesson-03__b15", "inline": [{"t": "emphasis", "s": "فهذا وما أشبهه مما صح سنده", "role": "emphasis"}, {"t": "text", "s": ": نؤمن به، ولا نرده ولا نجحده ولا نتأوله بتأويل يخالف ظاهره، ولا نشبهه بصفات المخلوقين، ولا نمثله ولا نكيفه، ونعتقد فيه ما ثبت في كتابه، وسنة نبيه "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " ، ونقطع الوهم والظن عن غير ذلك؛ فالله "}, {"t": "honorific", "s": "سبحانه وتعالى"}, {"t": "text", "s": " : "}, {"t": "ayah", "s": "لَيۡسَ كَمِثۡلِهِۦ شَيۡءٞۖ وَهُوَ ٱلسَّمِيعُ ٱلۡبَصِيرُ ۝١١", "ayah": [11], "verses": [{"n": 11, "text": "لَيۡسَ كَمِثۡلِهِۦ شَيۡءٞۖ وَهُوَ ٱلسَّمِيعُ ٱلۡبَصِيرُ", "surah": 42, "ref_api": "https://api.quran.com/api/v4/verses/by_key/42:11", "surah_name": "الشورى", "ayah_canonical": 11, "match": "contained", "ref": "42:11"}], "surah": null, "ref_api": null}, {"t": "text", "s": "."}]}, {"type": "paragraph", "md": "- ومن ذلك: صفة الاستواء على العرش، والعلو؛ فقد قال تعالى: ﴿ٱلرَّحۡمَٰنُ عَلَى ٱلۡعَرۡشِ ٱسۡتَوَىٰ﴾، أي علا وارتفع، وقال تعالى: ﴿ءَأَمِنتُم مَّن فِي ٱلسَّمَآءِ أَن يَخۡسِفَ بِكُمُ ٱلۡأَرۡضَ﴾ فهو فوق السماء سبحانه وتعالى ، وقال النبي  صلى الله عليه وسلم للجارية: (أين الله؟ قالت: في السماء. قال: أعتقها فإنها مؤمنة)، فهذا وما أشبههه مما أجمع السلف رحمهم الله على نقله وقبوله، ولم يتعرضوا لرده ولا تأويله، ولا تشبيهه ولا تمثيله، وآمنوا به على حقيقته.", "page": 108, "id": "unit-10__lesson-03__b16", "inline": [{"t": "text", "s": "- ومن ذلك: صفة "}, {"t": "emphasis", "s": "الاستواء على العرش، والعلو", "role": "emphasis"}, {"t": "text", "s": "؛ فقد قال تعالى: "}, {"t": "ayah", "s": "ٱلرَّحۡمَٰنُ عَلَى ٱلۡعَرۡشِ ٱسۡتَوَىٰ", "ayah": [], "verses": [{"n": 5, "text": "ٱلرَّحۡمَٰنُ عَلَى ٱلۡعَرۡشِ ٱسۡتَوَىٰ", "surah": 20, "surah_name": "طه", "ref": "20:5", "ref_api": "https://api.quran.com/api/v4/verses/by_key/20:5"}], "surah": 20, "ref_api": "https://api.quran.com/api/v4/verses/by_key/20:5", "surah_name": "طه", "ayah_canonical": 5, "match": "exact", "ref": "20:5"}, {"t": "text", "s": "، أي علا وارتفع، وقال تعالى: "}, {"t": "ayah", "s": "ءَأَمِنتُم مَّن فِي ٱلسَّمَآءِ أَن يَخۡسِفَ بِكُمُ ٱلۡأَرۡضَ", "ayah": [], "verses": [{"n": 16, "text": "ءَأَمِنتُم مَّن فِي ٱلسَّمَآءِ أَن يَخۡسِفَ بِكُمُ ٱلۡأَرۡضَ", "surah": 67, "surah_name": "الملك", "ref": "67:16", "ref_api": "https://api.quran.com/api/v4/verses/by_key/67:16"}], "surah": 67, "ref_api": "https://api.quran.com/api/v4/verses/by_key/67:16", "surah_name": "الملك", "ayah_canonical": 16, "match": "contained", "ref": "67:16"}, {"t": "text", "s": " فهو فوق السماء "}, {"t": "honorific", "s": "سبحانه وتعالى"}, {"t": "text", "s": " ، وقال النبي  "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " للجارية: "}, {"t": "emphasis", "s": "(أين الله؟ قالت: في السماء. قال: أعتقها فإنها مؤمنة)", "role": "emphasis"}, {"t": "text", "s": "، فهذا وما أشبههه مما أجمع السلف "}, {"t": "honorific", "s": "رحمهم الله"}, {"t": "text", "s": " على نقله وقبوله، ولم يتعرضوا لرده ولا تأويله، ولا تشبيهه ولا تمثيله، وآمنوا به على حقيقته."}], "list": {"type": "unordered"}}, {"type": "paragraph", "md": "سئل الإمام مالك بن أنس رحمه الله : يا أبا عبد الله؛ كيف استوى؟ فقال: «الاستواء غير مجهول، والكيف غير معقول، والإيمان به واجب، والسؤال عنه بدعة..» ثم أمر بالرجل فأخرج؛ لأنه متعنت في السؤال.", "page": 108, "id": "unit-10__lesson-03__b17", "inline": [{"t": "text", "s": "سئل الإمام مالك بن أنس "}, {"t": "honorific", "s": "رحمه الله"}, {"t": "text", "s": " : يا أبا عبد الله؛ كيف استوى؟ فقال: "}, {"t": "quote", "s": "الاستواء غير مجهول، والكيف غير معقول، والإيمان به واجب، والسؤال عنه بدعة.."}, {"t": "text", "s": " ثم أمر بالرجل فأخرج؛ لأنه متعنت في السؤال."}]}, {"type": "paragraph", "md": "كلام الله: ومن صفات الله تعالى أنه متكلم بكلام (وصفة كلام الله -كسائر صفاته عز وجل -قديمة غير مُحدثة) يسمعه منه مَن شاء من خلقه؛ سمعه موسى عليه السلام منه من غير واسطة، وسمعه جبريل عليه السلام ، ومَن أذن له من ملائكته ورسله، ونؤمن أنه سبحانه يكلم المؤمنين في الآخرة ويكلمونه، ويأذن لهم فيزورونه.", "page": 108, "id": "unit-10__lesson-03__b18", "inline": [{"t": "emphasis", "s": "كلام الله:", "role": "emphasis"}, {"t": "text", "s": " ومن صفات الله تعالى أنه متكلم بكلام "}, {"t": "emphasis", "s": "(وصفة كلام الله -كسائر صفاته", "role": "emphasis"}, {"t": "text", "s": " "}, {"t": "honorific", "s": "عز وجل"}, {"t": "text", "s": " "}, {"t": "emphasis", "s": "-قديمة غير مُحدثة)", "role": "emphasis"}, {"t": "text", "s": " يسمعه منه مَن شاء من خلقه؛ سمعه موسى "}, {"t": "honorific", "s": "عليه السلام"}, {"t": "text", "s": " منه من غير واسطة، وسمعه جبريل "}, {"t": "honorific", "s": "عليه السلام"}, {"t": "text", "s": " ، ومَن أذن له من ملائكته ورسله، ونؤمن أنه سبحانه يكلم المؤمنين في الآخرة ويكلمونه، ويأذن لهم فيزورونه."}]}, {"type": "paragraph", "md": "قال الله تعالى: ﴿وَكَلَّمَ ٱللَّهُ مُوسَىٰ تَكۡلِيمٗا ۝١٦٤﴾، وقال سبحانه وتعالى : ﴿إِنِّي ٱصۡطَفَيۡتُكَ عَلَى ٱلنَّاسِ بِرِسَٰلَٰتِي وَبِكَلَٰمِي﴾، وقال سبحانه وتعالى : { تِلْكَ الرُّسُلُ فَضَّلْنَا بَعْضَهُمْ عَلَى بَعْضٍ مِنْهُمْ مَنْ كَلَّمَ اللَّهُ وَرَفَعَ بَعْضَهُمْ دَرَجَاتٍ}، وقال سبحانه: ﴿۞وَمَا كَانَ لِبَشَرٍ أَن يُكَلِّمَهُ ٱللَّهُ إِلَّا وَحۡيًا أَوۡ مِن وَرَآيِٕ حِجَابٍ﴾، وقال سبحانه: ﴿إِنَّنِيٓ أَنَا ٱللَّهُ لَآ إِلَٰهَ إِلَّآ أَنَا۠ فَٱعۡبُدۡنِي وَأَقِمِ ٱلصَّلَوٰةَ لِذِكۡرِيٓ ۝١٤﴾، وغير جائز أن يقول قائل: هذا أحد غير الله!! عياذًا بالله.", "page": 108, "id": "unit-10__lesson-03__b19", "inline": [{"t": "text", "s": "قال الله تعالى: "}, {"t": "ayah", "s": "وَكَلَّمَ ٱللَّهُ مُوسَىٰ تَكۡلِيمٗا ۝١٦٤", "ayah": [164], "verses": [{"n": 164, "text": "وَكَلَّمَ ٱللَّهُ مُوسَىٰ تَكۡلِيمٗا", "surah": 4, "ref_api": "https://api.quran.com/api/v4/verses/by_key/4:164", "surah_name": "النساء", "ayah_canonical": 164, "match": "contained", "ref": "4:164"}], "surah": null, "ref_api": null}, {"t": "text", "s": "، وقال "}, {"t": "honorific", "s": "سبحانه وتعالى"}, {"t": "text", "s": " : "}, {"t": "ayah", "s": "إِنِّي ٱصۡطَفَيۡتُكَ عَلَى ٱلنَّاسِ بِرِسَٰلَٰتِي وَبِكَلَٰمِي", "ayah": [], "verses": [{"n": 144, "text": "إِنِّي ٱصۡطَفَيۡتُكَ عَلَى ٱلنَّاسِ بِرِسَٰلَٰتِ